#include "biblia.h"

void Biblia::CarregarJo(Biblia* b) {
    b->dados[JO].nome = _("Jó");

    b->dados[JO].capitulos[1].versos[1] = _("Havia um homem na terra de Uz, cujo nome era Jó. Era homem íntegro e reto, que temia a Deus e se desviava do mal.");
    b->dados[JO].capitulos[1].versos[2] = _("Nasceram-lhe sete filhos e três filhas.");
    b->dados[JO].capitulos[1].versos[3] = _("Possuía ele sete mil ovelhas, três mil camelos, quinhentas juntas de bois e quinhentas jumentas, tendo também muitíssima gente ao seu serviço; de modo que este homem era o maior de todos os do Oriente.");
    b->dados[JO].capitulos[1].versos[4] = _("Iam seus filhos à casa uns dos outros e faziam banquetes cada um por sua vez; e mandavam convidar as suas três irmãs para comerem e beberem com eles.");
    b->dados[JO].capitulos[1].versos[5] = _("E sucedia que, tendo decorrido o turno de dias de seus banquetes, enviava Jó e os santificava; e, levantando-se de madrugada, oferecia holocaustos segundo o número de todos eles; pois dizia Jó: Talvez meus filhos tenham pecado, e blasfemado de Deus no seu coração. Assim o fazia Jó continuamente.");
    b->dados[JO].capitulos[1].versos[6] = _("Ora, chegado o dia em que os filhos de Deus vieram apresentar-se perante o Senhor, veio também Satanás entre eles.");
    b->dados[JO].capitulos[1].versos[7] = _("O Senhor perguntou a Satanás: Donde vens? E Satanás respondeu ao Senhor, dizendo: De rodear a terra, e de passear por ela.");
    b->dados[JO].capitulos[1].versos[8] = _("Disse o Senhor a Satanás: Notaste porventura o meu servo Jó, que ninguém há na terra semelhante a ele, homem íntegro e reto, que teme a Deus e se desvia do mal?");
    b->dados[JO].capitulos[1].versos[9] = _("Então respondeu Satanás ao Senhor, e disse: Porventura Jó teme a Deus debalde?");
    b->dados[JO].capitulos[1].versos[10] = _("Não o tens protegido de todo lado a ele, a sua casa e a tudo quanto tem? Tens abençoado a obra de suas mãos, e os seus bens se multiplicam na terra.");
    b->dados[JO].capitulos[1].versos[11] = _("Mas estende agora a tua mão, e toca-lhe em tudo quanto tem, e ele blasfemará de ti na tua face!");
    b->dados[JO].capitulos[1].versos[12] = _("Ao que disse o Senhor a Satanás: Eis que tudo o que ele tem está no teu poder; somente contra ele não estendas a tua mão. E Satanás saiu da presença do Senhor.");
    b->dados[JO].capitulos[1].versos[13] = _("Certo dia, quando seus filhos e suas filhas comiam e bebiam vinho em casa do irmão mais velho,");
    b->dados[JO].capitulos[1].versos[14] = _("veio um mensageiro a Jó e lhe disse: Os bois lavravam, e as jumentas pasciam junto a eles;");
    b->dados[JO].capitulos[1].versos[15] = _("e deram sobre eles os sabeus, e os tomaram; mataram os moços ao fio da espada, e só eu escapei para trazer-te a nova.");
    b->dados[JO].capitulos[1].versos[16] = _("Enquanto este ainda falava, veio outro e disse: Fogo de Deus caiu do céu e queimou as ovelhas e os moços, e os consumiu; e só eu escapei para trazer-te a nova.");
    b->dados[JO].capitulos[1].versos[17] = _("Enquanto este ainda falava, veio outro e disse: Os caldeus, dividindo-se em três bandos, deram sobre os camelos e os tomaram; e mataram os moços ao fio da espada; e só eu escapei para trazer-te a nova.");
    b->dados[JO].capitulos[1].versos[18] = _("Enquanto este ainda falava, veio outro e disse: Teus filhos e tuas filhas estavam comendo e bebendo vinho em casa do irmão mais velho;");
    b->dados[JO].capitulos[1].versos[19] = _("e eis que sobrevindo um grande vento de além do deserto, deu nos quatro cantos da casa, e ela caiu sobre os mancebos, de sorte que morreram; e só eu escapei para trazer-te a nova.");
    b->dados[JO].capitulos[1].versos[20] = _("Então Jó se levantou, rasgou o seu manto, rapou a sua cabeça e, lançando-se em terra, adorou;");
    b->dados[JO].capitulos[1].versos[21] = _("e disse: Nu saí do ventre de minha mãe, e nu tornarei para lá. O Senhor deu, e o Senhor tirou; bendito seja o nome do Senhor.");
    b->dados[JO].capitulos[1].versos[22] = _("Em tudo isso Jó não pecou, nem atribuiu a Deus falta alguma.");

    b->dados[JO].capitulos[2].versos[1] = _("Chegou outra vez o dia em que os filhos de Deus vieram apresentar-se perante o Senhor; e veio também Satanás entre eles apresentar-se perante o Senhor.");
    b->dados[JO].capitulos[2].versos[2] = _("Então o Senhor perguntou a Satanás: Donde vens? Respondeu Satanás ao Senhor, dizendo: De rodear a terra, e de passear por ela.");
    b->dados[JO].capitulos[2].versos[3] = _("Disse o Senhor a Satanás: Notaste porventura o meu servo Jó, que ninguém há na terra semelhante a ele, homem íntegro e reto, que teme a Deus e se desvia do mal? Ele ainda retém a sua integridade, embora me incitasses contra ele, para o consumir sem causa.");
    b->dados[JO].capitulos[2].versos[4] = _("Então Satanás respondeu ao Senhor: Pele por pele! Tudo quanto o homem tem dará pela sua vida.");
    b->dados[JO].capitulos[2].versos[5] = _("Estende agora a mão, e toca-lhe nos ossos e na carne, e ele blasfemará de ti na tua face!");
    b->dados[JO].capitulos[2].versos[6] = _("Disse, pois, o Senhor a Satanás: Eis que ele está no teu poder; somente poupa-lhe a vida.");
    b->dados[JO].capitulos[2].versos[7] = _("Saiu, pois, Satanás da presença do Senhor, e feriu Jó de úlceras malignas, desde a planta do pé até o alto da cabeça.");
    b->dados[JO].capitulos[2].versos[8] = _("E Jó, tomando um caco para com ele se raspar, sentou-se no meio da cinza.");
    b->dados[JO].capitulos[2].versos[9] = _("Então sua mulher lhe disse: Ainda reténs a tua integridade? Blasfema de Deus, e morre.");
    b->dados[JO].capitulos[2].versos[10] = _("Mas ele lhe disse: Como fala qualquer doida, assim falas tu; receberemos de Deus o bem, e não receberemos o mal? Em tudo isso não pecou Jó com os seus lábios.");
    b->dados[JO].capitulos[2].versos[11] = _("Ouvindo, pois, três amigos de Jó todo esse mal que lhe havia sucedido, vieram, cada um do seu lugar: Elifaz o temanita, Bildade o suíta e Zofar o naamatita; pois tinham combinado para virem condoer-se dele e consolá-lo.");
    b->dados[JO].capitulos[2].versos[12] = _("E, levantando de longe os olhos e não o reconhecendo, choraram em alta voz; e, rasgando cada um o seu manto, lançaram pó para o ar sobre as suas cabeças.");
    b->dados[JO].capitulos[2].versos[13] = _("E ficaram sentados com ele na terra sete dias e sete noites; e nenhum deles lhe dizia palavra alguma, pois viam que a dor era muito grande.");

    b->dados[JO].capitulos[3].versos[1] = _("Depois disso abriu Jó a sua boca, e amaldiçoou o seu dia.");
    b->dados[JO].capitulos[3].versos[2] = _("E Jó falou, dizendo:");
    b->dados[JO].capitulos[3].versos[3] = _("Pereça o dia em que nasci, e a noite que se disse: Foi concebido um homem!");
    b->dados[JO].capitulos[3].versos[4] = _("Converta-se aquele dia em trevas; e Deus, lá de cima, não tenha cuidado dele, nem resplandeça sobre ele a luz.");
    b->dados[JO].capitulos[3].versos[5] = _("Reclamem-no para si as trevas e a sombra da morte; habitem sobre ele nuvens; espante-o tudo o que escurece o dia.");
    b->dados[JO].capitulos[3].versos[6] = _("Quanto àquela noite, dela se apodere a escuridão; e não se regozije ela entre os dias do ano; e não entre no número dos meses.");
    b->dados[JO].capitulos[3].versos[7] = _("Ah! que estéril seja aquela noite, e nela não entre voz de regozijo.");
    b->dados[JO].capitulos[3].versos[8] = _("Amaldiçoem-na aqueles que amaldiçoam os dias, que são peritos em suscitar o leviatã.");
    b->dados[JO].capitulos[3].versos[9] = _("As estrelas da alva se lhe escureçam; espere ela em vão a luz, e não veja as pálpebras da manhã;");
    b->dados[JO].capitulos[3].versos[10] = _("porquanto não fechou as portas do ventre de minha mãe, nem escondeu dos meus olhos a aflição.");
    b->dados[JO].capitulos[3].versos[11] = _("Por que não morri ao nascer? por que não expirei ao vir à luz?");
    b->dados[JO].capitulos[3].versos[12] = _("Por que me receberam os joelhos? e por que os seios, para que eu mamasse?");
    b->dados[JO].capitulos[3].versos[13] = _("Pois agora eu estaria deitado e quieto; teria dormido e estaria em repouso,");
    b->dados[JO].capitulos[3].versos[14] = _("com os reis e conselheiros da terra, que reedificavam ruínas para si,");
    b->dados[JO].capitulos[3].versos[15] = _("ou com os príncipes que tinham ouro, que enchiam as suas casas de prata;");
    b->dados[JO].capitulos[3].versos[16] = _("ou, como aborto oculto, eu não teria existido, como as crianças que nunca viram a luz.");
    b->dados[JO].capitulos[3].versos[17] = _("Ali os ímpios cessam de perturbar; e ali repousam os cansados.");
    b->dados[JO].capitulos[3].versos[18] = _("Ali os presos descansam juntos, e não ouvem a voz do exator.");
    b->dados[JO].capitulos[3].versos[19] = _("O pequeno e o grande ali estão e o servo está livre de seu senhor.");
    b->dados[JO].capitulos[3].versos[20] = _("Por que se concede luz ao aflito, e vida aos amargurados de alma;");
    b->dados[JO].capitulos[3].versos[21] = _("que anelam pela morte sem que ela venha, e cavam em procura dela mais do que de tesouros escondidos;");
    b->dados[JO].capitulos[3].versos[22] = _("que muito se regozijam e exultam, quando acham a sepultura?");
    b->dados[JO].capitulos[3].versos[23] = _("Sim, por que se concede luz ao homem cujo caminho está escondido, e a quem Deus cercou de todos os lados?");
    b->dados[JO].capitulos[3].versos[24] = _("Pois em lugar de meu pão vem o meu suspiro, e os meus gemidos se derramam como água.");
    b->dados[JO].capitulos[3].versos[25] = _("Porque aquilo que temo me sobrevém, e o que receio me acontece.");
    b->dados[JO].capitulos[3].versos[26] = _("Não tenho repouso, nem sossego, nem descanso; mas vem a perturbação.");

    b->dados[JO].capitulos[4].versos[1] = _("Então respondeu Elifaz, o temanita, e disse:");
    b->dados[JO].capitulos[4].versos[2] = _("Se alguém intentar falar-te, enfadarte-ás? Mas quem poderá conter as palavras?");
    b->dados[JO].capitulos[4].versos[3] = _("Eis que tens ensinado a muitos, e tens fortalecido as mãos fracas.");
    b->dados[JO].capitulos[4].versos[4] = _("As tuas palavras têm sustentado aos que cambaleavam, e os joelhos desfalecentes tens fortalecido.");
    b->dados[JO].capitulos[4].versos[5] = _("Mas agora que se trata de ti, te enfadas; e, tocando-te a ti, te desanimas.");
    b->dados[JO].capitulos[4].versos[6] = _("Porventura não está a tua confiança no teu temor de Deus, e a tua esperança na integridade dos teus caminhos?");
    b->dados[JO].capitulos[4].versos[7] = _("Lembra-te agora disto: qual o inocente que jamais pereceu? E onde foram os retos destruídos?");
    b->dados[JO].capitulos[4].versos[8] = _("Conforme tenho visto, os que lavram iniquidade e semeiam o mal segam o mesmo.");
    b->dados[JO].capitulos[4].versos[9] = _("Pelo sopro de Deus perecem, e pela rajada da sua ira são consumidos.");
    b->dados[JO].capitulos[4].versos[10] = _("Cessa o rugido do leão, e a voz do leão feroz; os dentes dos leõezinhos se quebram.");
    b->dados[JO].capitulos[4].versos[11] = _("Perece o leão velho por falta de presa, e os filhotes da leoa andam dispersos.");
    b->dados[JO].capitulos[4].versos[12] = _("Ora, uma palavra se me disse em segredo, e os meus ouvidos perceberam um sussurro dela.");
    b->dados[JO].capitulos[4].versos[13] = _("Entre pensamentos nascidos de visões noturnas, quando cai sobre os homens o sono profundo,");
    b->dados[JO].capitulos[4].versos[14] = _("sobrevieram-me o espanto e o tremor, que fizeram estremecer todos os meus ossos.");
    b->dados[JO].capitulos[4].versos[15] = _("Então um espírito passou por diante de mim; arrepiaram-se os cabelos do meu corpo.");
    b->dados[JO].capitulos[4].versos[16] = _("Parou ele, mas não pude discernir a sua aparência; um vulto estava diante dos meus olhos; houve silêncio, então ouvi uma voz que dizia:");
    b->dados[JO].capitulos[4].versos[17] = _("Pode o homem mortal ser justo diante de Deus? Pode o varão ser puro diante do seu Criador?");
    b->dados[JO].capitulos[4].versos[18] = _("Eis que Deus não confia nos seus servos, e até a seus anjos atribui loucura;");
    b->dados[JO].capitulos[4].versos[19] = _("quanto mais aos que habitam em casas de lodo, cujo fundamento está no pó, e que são esmagados pela traça!");
    b->dados[JO].capitulos[4].versos[20] = _("Entre a manhã e a tarde são destruídos; perecem para sempre sem que disso se faça caso.");
    b->dados[JO].capitulos[4].versos[21] = _("Se dentro deles é arrancada a corda da sua tenda, porventura não morrem, e isso sem atingir a sabedoria?");

    b->dados[JO].capitulos[5].versos[1] = _("Chama agora; há alguém que te responda; E a qual dentre os entes santos te dirigirás?");
    b->dados[JO].capitulos[5].versos[2] = _("Pois a dor destrói o louco, e a inveja mata o tolo.");
    b->dados[JO].capitulos[5].versos[3] = _("Bem vi eu o louco lançar raízes; mas logo amaldiçoei a sua habitação:");
    b->dados[JO].capitulos[5].versos[4] = _("Seus filhos estão longe da segurança, e são pisados nas portas, e não há quem os livre.");
    b->dados[JO].capitulos[5].versos[5] = _("A sua messe é devorada pelo faminto, que até dentre os espinhos a tira; e o laço abre as fauces para a fazenda deles.");
    b->dados[JO].capitulos[5].versos[6] = _("Porque a aflição não procede do pó, nem a tribulação brota da terra;");
    b->dados[JO].capitulos[5].versos[7] = _("mas o homem nasce para a tribulação, como as faíscas voam para cima.");
    b->dados[JO].capitulos[5].versos[8] = _("Mas quanto a mim eu buscaria a Deus, e a Deus entregaria a minha causa;");
    b->dados[JO].capitulos[5].versos[9] = _("o qual faz coisas grandes e inescrutáveis, maravilhas sem número.");
    b->dados[JO].capitulos[5].versos[10] = _("Ele derrama a chuva sobre a terra, e envia águas sobre os campos.");
    b->dados[JO].capitulos[5].versos[11] = _("Ele põe num lugar alto os abatidos; e os que choram são exaltados à segurança.");
    b->dados[JO].capitulos[5].versos[12] = _("Ele frustra as maquinações dos astutos, de modo que as suas mãos não possam levar coisa alguma a efeito.");
    b->dados[JO].capitulos[5].versos[13] = _("Ele apanha os sábios na sua própria astúcia, e o conselho dos perversos se precipita.");
    b->dados[JO].capitulos[5].versos[14] = _("Eles de dia encontram as trevas, e ao meio-dia andam às apalpadelas, como de noite.");
    b->dados[JO].capitulos[5].versos[15] = _("Mas Deus livra o necessitado da espada da boca deles, e da mão do poderoso.");
    b->dados[JO].capitulos[5].versos[16] = _("Assim há esperança para o pobre; e a iniqüidade tapa a boca.");
    b->dados[JO].capitulos[5].versos[17] = _("Eis que bem-aventurado é o homem a quem Deus corrige; não desprezes, pois, a correção do Todo-Poderoso.");
    b->dados[JO].capitulos[5].versos[18] = _("Pois ele faz a ferida, e ele mesmo a liga; ele fere, e as suas mãos curam.");
    b->dados[JO].capitulos[5].versos[19] = _("Em seis angústias te livrará, e em sete o mal não te tocará.");
    b->dados[JO].capitulos[5].versos[20] = _("Na fome te livrará da morte, e na guerra do poder da espada.");
    b->dados[JO].capitulos[5].versos[21] = _("Do açoite da língua estarás abrigado, e não temerás a assolação, quando chegar.");
    b->dados[JO].capitulos[5].versos[22] = _("Da assolação e da fome te rirás, e dos animais da terra não terás medo.");
    b->dados[JO].capitulos[5].versos[23] = _("Pois até com as pedras do campo terás a tua aliança, e as feras do campo estarão em paz contigo.");
    b->dados[JO].capitulos[5].versos[24] = _("Saberás que a tua tenda está em paz; visitarás o teu rebanho, e nada te faltará.");
    b->dados[JO].capitulos[5].versos[25] = _("Também saberás que se multiplicará a tua descendência e a tua posteridade como a erva da terra.");
    b->dados[JO].capitulos[5].versos[26] = _("Em boa velhice irás à sepultura, como se recolhe o feixe de trigo a seu tempo.");
    b->dados[JO].capitulos[5].versos[27] = _("Eis que isso já o havemos inquirido, e assim o é; ouve-o, e conhece-o para teu bem.");

    b->dados[JO].capitulos[6].versos[1] = _("Então Jó, respondendo, disse:");
    b->dados[JO].capitulos[6].versos[2] = _("Oxalá de fato se pesasse a minha mágoa, e juntamente na balança se pusesse a minha calamidade!");
    b->dados[JO].capitulos[6].versos[3] = _("Pois, na verdade, seria mais pesada do que a areia dos mares; por isso é que as minhas palavras têm sido temerárias.");
    b->dados[JO].capitulos[6].versos[4] = _("Porque as flechas do Todo-Poderoso se cravaram em mim, e o meu espírito suga o veneno delas; os terrores de Deus se arregimentam contra mim.");
    b->dados[JO].capitulos[6].versos[5] = _("Zurrará o asno montês quando tiver erva? Ou mugirá o boi junto ao seu pasto?:");
    b->dados[JO].capitulos[6].versos[6] = _("Pode se comer sem sal o que é insípido? Ou há gosto na clara do ovo?");
    b->dados[JO].capitulos[6].versos[7] = _("Nessas coisas a minha alma recusa tocar, pois são para mim qual comida repugnante.");
    b->dados[JO].capitulos[6].versos[8] = _("Quem dera que se cumprisse o meu rogo, e que Deus me desse o que anelo!");
    b->dados[JO].capitulos[6].versos[9] = _("que fosse do agrado de Deus esmagar-me; que soltasse a sua mão, e me exterminasse!");
    b->dados[JO].capitulos[6].versos[10] = _("Isto ainda seria a minha consolação, e exultaria na dor que não me poupa; porque não tenho negado as palavras do Santo.");
    b->dados[JO].capitulos[6].versos[11] = _("Qual é a minha força, para que eu espere? Ou qual é o meu fim, para que me porte com paciência?");
    b->dados[JO].capitulos[6].versos[12] = _("É a minha força a força da pedra? Ou é de bronze a minha carne?");
    b->dados[JO].capitulos[6].versos[13] = _("Na verdade não há em mim socorro nenhum. Não me desamparou todo o auxílio eficaz?");
    b->dados[JO].capitulos[6].versos[14] = _("Ao que desfalece devia o amigo mostrar compaixão; mesmo ao que abandona o temor do Todo-Poderoso.");
    b->dados[JO].capitulos[6].versos[15] = _("Meus irmãos houveram-se aleivosamente, como um ribeiro, como a torrente dos ribeiros que passam,");
    b->dados[JO].capitulos[6].versos[16] = _("os quais se turvam com o gelo, e neles se esconde a neve;");
    b->dados[JO].capitulos[6].versos[17] = _("no tempo do calor vão minguando; e quando o calor vem, desaparecem do seu lugar.");
    b->dados[JO].capitulos[6].versos[18] = _("As caravanas se desviam do seu curso; sobem ao deserto, e perecem.");
    b->dados[JO].capitulos[6].versos[19] = _("As caravanas de Tema olham; os viandantes de Sabá por eles esperam.");
    b->dados[JO].capitulos[6].versos[20] = _("Ficam envergonhados por terem confiado; e, chegando ali, se confundem.");
    b->dados[JO].capitulos[6].versos[21] = _("Agora, pois, tais vos tornastes para mim; vedes a minha calamidade e temeis.");
    b->dados[JO].capitulos[6].versos[22] = _("Acaso disse eu: Dai-me um presente? Ou: Fazei-me uma oferta de vossos bens?");
    b->dados[JO].capitulos[6].versos[23] = _("Ou: Livrai-me das mãos do adversário? Ou: Resgatai-me das mãos dos opressores ?");
    b->dados[JO].capitulos[6].versos[24] = _("Ensinai-me, e eu me calarei; e fazei-me entender em que errei.");
    b->dados[JO].capitulos[6].versos[25] = _("Quão poderosas são as palavras da boa razão! Mas que é o que a vossa argüição reprova?");
    b->dados[JO].capitulos[6].versos[26] = _("Acaso pretendeis reprovar palavras, embora sejam as razões do desesperado como vento?");
    b->dados[JO].capitulos[6].versos[27] = _("Até quereis lançar sortes sobre o órfão, e fazer mercadoria do vosso amigo.");
    b->dados[JO].capitulos[6].versos[28] = _("Agora, pois, por favor, olhai para, mim; porque de certo à vossa face não mentirei.");
    b->dados[JO].capitulos[6].versos[29] = _("Mudai de parecer, peço-vos, não haja injustiça; sim, mudai de parecer, que a minha causa é justa.");
    b->dados[JO].capitulos[6].versos[30] = _("Há iniqüidade na minha língua? Ou não poderia o meu paladar discernir coisas perversas?");

    b->dados[JO].capitulos[7].versos[1] = _("Porventura não tem o homem duro serviço sobre a terra? E não são os seus dias como os do jornaleiro?");
    b->dados[JO].capitulos[7].versos[2] = _("Como o escravo que suspira pela sombra, e como o jornaleiro que espera pela sua paga,");
    b->dados[JO].capitulos[7].versos[3] = _("assim se me deram meses de escassez, e noites de aflição se me ordenaram.");
    b->dados[JO].capitulos[7].versos[4] = _("Havendo-me deitado, digo: Quando me levantarei? Mas comprida é a noite, e farto-me de me revolver na cama até a alva.");
    b->dados[JO].capitulos[7].versos[5] = _("A minha carne se tem vestido de vermes e de torrões de pó; a minha pele endurece, e torna a rebentar-se.");
    b->dados[JO].capitulos[7].versos[6] = _("Os meus dias são mais velozes do que a lançadeira do tecelão, e chegam ao fim sem esperança.");
    b->dados[JO].capitulos[7].versos[7] = _("Lembra-te de que a minha vida é um sopro; os meus olhos não tornarão a ver o bem.");
    b->dados[JO].capitulos[7].versos[8] = _("Os olhos dos que agora me vêem não me verão mais; os teus olhos estarão sobre mim, mas não serei mais.");
    b->dados[JO].capitulos[7].versos[9] = _("Tal como a nuvem se desfaz e some, aquele que desce à sepultura nunca tornará a subir.");
    b->dados[JO].capitulos[7].versos[10] = _("Nunca mais tornará à sua casa, nem o seu lugar o conhecerá mais.");
    b->dados[JO].capitulos[7].versos[11] = _("Por isso não reprimirei a minha boca; falarei na angústia do meu espírito, queixar-me-ei na amargura da minha alma.");
    b->dados[JO].capitulos[7].versos[12] = _("Sou eu o mar, ou um monstro marinho, para que me ponhas uma guarda?");
    b->dados[JO].capitulos[7].versos[13] = _("Quando digo: Confortar-me-á a minha cama, meu leito aliviará a minha queixa,");
    b->dados[JO].capitulos[7].versos[14] = _("então me espantas com sonhos, e com visões me atemorizas;");
    b->dados[JO].capitulos[7].versos[15] = _("de modo que eu escolheria antes a estrangulação, e a morte do que estes meus ossos.");
    b->dados[JO].capitulos[7].versos[16] = _("A minha vida abomino; não quero viver para sempre; retira-te de mim, pois os meus dias são vaidade.");
    b->dados[JO].capitulos[7].versos[17] = _("Que é o homem, para que tanto o engrandeças, e ponhas sobre ele o teu pensamento,");
    b->dados[JO].capitulos[7].versos[18] = _("e cada manhã o visites, e cada momento o proves?");
    b->dados[JO].capitulos[7].versos[19] = _("Até quando não apartarás de mim a tua vista, nem me largarás, até que eu possa engolir a minha saliva?");
    b->dados[JO].capitulos[7].versos[20] = _("Se peco, que te faço a ti, ó vigia dos homens? Por que me fizeste alvo dos teus dardos? Por que a mim mesmo me tornei pesado?");
    b->dados[JO].capitulos[7].versos[21] = _("Por que me não perdoas a minha transgressão, e não tiras a minha iniqüidade? Pois agora me deitarei no pó; tu me buscarás, porém eu não serei mais.");

    b->dados[JO].capitulos[8].versos[1] = _("Então respondeu Bildade, o suíta, dizendo:");
    b->dados[JO].capitulos[8].versos[2] = _("Até quando falarás tais coisas, e até quando serão as palavras da tua boca qual vento impetuoso?");
    b->dados[JO].capitulos[8].versos[3] = _("Perverteria Deus o direito? Ou perverteria o Todo-Poderoso a justiça?");
    b->dados[JO].capitulos[8].versos[4] = _("Se teus filhos pecaram contra ele, ele os entregou ao poder da sua transgressão.");
    b->dados[JO].capitulos[8].versos[5] = _("Mas, se tu com empenho buscares a Deus, e ,ao Todo-Poderoso fizeres a tua súplica,");
    b->dados[JO].capitulos[8].versos[6] = _("se fores puro e reto, certamente mesmo agora ele despertará por ti, e tornará segura a habitação da tua justiça.");
    b->dados[JO].capitulos[8].versos[7] = _("Embora tenha sido pequeno o teu princípio, contudo o teu último estado aumentará grandemente.");
    b->dados[JO].capitulos[8].versos[8] = _("Indaga, pois, eu te peço, da geração passada, e considera o que seus pais descobriram.");
    b->dados[JO].capitulos[8].versos[9] = _("Porque nós somos de ontem, e nada sabemos, porquanto nossos dias sobre a terra, são uma sombra.");
    b->dados[JO].capitulos[8].versos[10] = _("Não te ensinarão eles, e não te falarão, e do seu entendimento não proferirão palavras?");
    b->dados[JO].capitulos[8].versos[11] = _("Pode o papiro desenvolver-se fora de um pântano. Ou pode o junco crescer sem água?");
    b->dados[JO].capitulos[8].versos[12] = _("Quando está em flor e ainda não cortado, seca-se antes de qualquer outra erva.");
    b->dados[JO].capitulos[8].versos[13] = _("Assim são as veredas de todos quantos se esquecem de Deus; a esperança do ímpio perecerá,");
    b->dados[JO].capitulos[8].versos[14] = _("a sua segurança se desfará, e a sua confiança será como a teia de aranha.");
    b->dados[JO].capitulos[8].versos[15] = _("Encostar-se-á à sua casa, porém ela não subsistirá; apegar-se-lhe-á, porém ela não permanecerá.");
    b->dados[JO].capitulos[8].versos[16] = _("Ele está verde diante do sol, e os seus renovos estendem-se sobre o seu jardim;");
    b->dados[JO].capitulos[8].versos[17] = _("as suas raízes se entrelaçam junto ao monte de pedras; até penetra o pedregal.");
    b->dados[JO].capitulos[8].versos[18] = _("Mas quando for arrancado do seu lugar, então este o negará, dizendo: Nunca te vi.");
    b->dados[JO].capitulos[8].versos[19] = _("Eis que tal é a alegria do seu caminho; e da terra outros brotarão.");
    b->dados[JO].capitulos[8].versos[20] = _("Eis que Deus não rejeitará ao reto, nem tomará pela mão os malfeitores;");
    b->dados[JO].capitulos[8].versos[21] = _("ainda de riso te encherá a boca, e os teus lábios de louvor.");
    b->dados[JO].capitulos[8].versos[22] = _("Teus aborrecedores se vestirão de confusão; e a tenda dos ímpios não subsistirá.");

    b->dados[JO].capitulos[9].versos[1] = _("Então Jó respondeu, dizendo:");
    b->dados[JO].capitulos[9].versos[2] = _("Na verdade sei que assim é; mas como pode o homem ser justo para com Deus?");
    b->dados[JO].capitulos[9].versos[3] = _("Se alguém quisesse contender com ele, não lhe poderia responder uma vez em mil.");
    b->dados[JO].capitulos[9].versos[4] = _("Ele é sábio de coração e poderoso em forças; quem se endureceu contra ele, e ficou seguro?");
    b->dados[JO].capitulos[9].versos[5] = _("Ele é o que remove os montes, sem que o saibam, e os transtorna no seu furor;");
    b->dados[JO].capitulos[9].versos[6] = _("o que sacode a terra do seu lugar, de modo que as suas colunas estremecem;");
    b->dados[JO].capitulos[9].versos[7] = _("o que dá ordens ao sol, e ele não nasce; o que sela as estrelas;");
    b->dados[JO].capitulos[9].versos[8] = _("o que sozinho estende os céus, e anda sobre as ondas do mar;");
    b->dados[JO].capitulos[9].versos[9] = _("o que fez a ursa, o Oriom, e as Plêiades, e as recâmaras do sul;");
    b->dados[JO].capitulos[9].versos[10] = _("o que faz coisas grandes e insondáveis, e maravilhas que não se podem contar.");
    b->dados[JO].capitulos[9].versos[11] = _("Eis que ele passa junto a mim, e, não o vejo; sim, vai passando adiante, mas não o percebo.");
    b->dados[JO].capitulos[9].versos[12] = _("Eis que arrebata a presa; quem o pode impedir? Quem lhe dirá: Que é o que fazes?");
    b->dados[JO].capitulos[9].versos[13] = _("Deus não retirará a sua ira; debaixo dele se curvaram os aliados de Raabe;");
    b->dados[JO].capitulos[9].versos[14] = _("quanto menos lhe poderei eu responder ou escolher as minhas palavras para discutir com ele?");
    b->dados[JO].capitulos[9].versos[15] = _("Embora, eu seja justo, não lhe posso responder; tenho de pedir misericórdia ao meu juiz.");
    b->dados[JO].capitulos[9].versos[16] = _("Ainda que eu chamasse, e ele me respondesse, não poderia crer que ele estivesse escutando a minha voz.");
    b->dados[JO].capitulos[9].versos[17] = _("Pois ele me quebranta com uma tempestade, e multiplica as minhas chagas sem causa.");
    b->dados[JO].capitulos[9].versos[18] = _("Não me permite respirar, antes me farta de amarguras.");
    b->dados[JO].capitulos[9].versos[19] = _("Se fosse uma prova de força, eis-me aqui, diria ele; e se fosse questão de juízo, quem o citaria para comparecer?");
    b->dados[JO].capitulos[9].versos[20] = _("Ainda que eu fosse justo, a minha própria boca me condenaria; ainda que eu fosse perfeito, então ela me declararia perverso:");
    b->dados[JO].capitulos[9].versos[21] = _("Eu sou inocente; não estimo a mim mesmo; desprezo a minha vida.");
    b->dados[JO].capitulos[9].versos[22] = _("Tudo é o mesmo, portanto digo: Ele destrói o reto e o ímpio.");
    b->dados[JO].capitulos[9].versos[23] = _("Quando o açoite mata de repente, ele zomba da calamidade dos inocentes.");
    b->dados[JO].capitulos[9].versos[24] = _("A terra está entregue nas mãos do ímpio. Ele cobre o rosto dos juízes; se não é ele, quem é, logo?");
    b->dados[JO].capitulos[9].versos[25] = _("Ora, os meus dias são mais velozes do que um correio; fogem, e não vêem o bem.");
    b->dados[JO].capitulos[9].versos[26] = _("Eles passam como balsas de junco, como águia que se lança sobre a presa.");
    b->dados[JO].capitulos[9].versos[27] = _("Se eu disser: Eu me esquecerei da minha queixa, mudarei o meu aspecto, e tomarei alento;");
    b->dados[JO].capitulos[9].versos[28] = _("então tenho pavor de todas as minhas dores; porque bem sei que não me terás por inocente.");
    b->dados[JO].capitulos[9].versos[29] = _("Eu serei condenado; por que, pois, trabalharei em vão?");
    b->dados[JO].capitulos[9].versos[30] = _("Se eu me lavar com água de neve, e limpar as minhas mãos com sabão,");
    b->dados[JO].capitulos[9].versos[31] = _("mesmo assim me submergirás no fosso, e as minhas próprias vestes me abominarão.");
    b->dados[JO].capitulos[9].versos[32] = _("Porque ele não é homem, como eu, para eu lhe responder, para nos encontrarmos em juízo.");
    b->dados[JO].capitulos[9].versos[33] = _("Não há entre nós árbitro para pôr a mão sobre nós ambos.");
    b->dados[JO].capitulos[9].versos[34] = _("Tire ele a sua vara de cima de mim, e não me amedronte o seu terror;");
    b->dados[JO].capitulos[9].versos[35] = _("então falarei, e não o temerei; pois eu não sou assim em mim mesmo.");

    b->dados[JO].capitulos[10].versos[1] = _("Tendo tédio à minha vida; darei livre curso à minha queixa, falarei na amargura da minha alma:");
    b->dados[JO].capitulos[10].versos[2] = _("Direi a Deus: Não me condenes; faze-me saber por que contendes comigo.");
    b->dados[JO].capitulos[10].versos[3] = _("Tens prazer em oprimir, em desprezar a obra das tuas mãos e favorecer o desígnio dos ímpios?");
    b->dados[JO].capitulos[10].versos[4] = _("Tens tu olhos de carne? Ou vês tu como vê o homem?");
    b->dados[JO].capitulos[10].versos[5] = _("São os teus dias como os dias do homem? Ou são os teus anos como os anos de um homem,");
    b->dados[JO].capitulos[10].versos[6] = _("para te informares da minha iniqüidade, e averiguares o meu pecado,");
    b->dados[JO].capitulos[10].versos[7] = _("ainda que tu sabes que eu não sou ímpio, e que não há ninguém que possa livrar-me da tua mão?");
    b->dados[JO].capitulos[10].versos[8] = _("As tuas mãos me fizeram e me deram forma; e te voltas agora para me consumir?");
    b->dados[JO].capitulos[10].versos[9] = _("Lembra-te, pois, de que do barro me formaste; e queres fazer-me tornar ao pó?");
    b->dados[JO].capitulos[10].versos[10] = _("Não me vazaste como leite, e não me coalhaste como queijo?");
    b->dados[JO].capitulos[10].versos[11] = _("De pele e carne me vestiste, e de ossos e nervos me teceste.");
    b->dados[JO].capitulos[10].versos[12] = _("Vida e misericórdia me tens concedido, e a tua providência me tem conservado o espírito.");
    b->dados[JO].capitulos[10].versos[13] = _("Contudo ocultaste estas coisas no teu coração; bem sei que isso foi o teu desígnio.");
    b->dados[JO].capitulos[10].versos[14] = _("Se eu pecar, tu me observas, e da minha iniqüidade não me absolverás.");
    b->dados[JO].capitulos[10].versos[15] = _("Se for ímpio, ai de mim! Se for justo, não poderei levantar a minha cabeça, estando farto de ignomínia, e de contemplar a minha miséria.");
    b->dados[JO].capitulos[10].versos[16] = _("Se a minha cabeça se exaltar, tu me caças como a um leão feroz; e de novo fazes maravilhas contra mim.");
    b->dados[JO].capitulos[10].versos[17] = _("Tu renovas contra mim as tuas testemunhas, e multiplicas contra mim a tua ira; reveses e combate estão comigo.");
    b->dados[JO].capitulos[10].versos[18] = _("Por que, pois, me tiraste da madre? Ah! se então tivera expirado, e olhos nenhuns me vissem!");
    b->dados[JO].capitulos[10].versos[19] = _("Então fora como se nunca houvera sido; e da madre teria sido levado para a sepultura.");
    b->dados[JO].capitulos[10].versos[20] = _("Não são poucos os meus dias? Cessa, pois, e deixa-me, para que por um pouco eu tome alento;");
    b->dados[JO].capitulos[10].versos[21] = _("antes que me vá para o lugar de que não voltarei, para a terra da escuridão e das densas trevas,");
    b->dados[JO].capitulos[10].versos[22] = _("terra escuríssima, como a própria escuridão, terra da sombra trevosa e do caos, e onde a própria luz é como a escuridão.");

    b->dados[JO].capitulos[11].versos[1] = _("Então respondeu Zofar, o naamatita, dizendo:");
    b->dados[JO].capitulos[11].versos[2] = _("Não se dará resposta à multidão de palavras? ou será justificado o homem falador?");
    b->dados[JO].capitulos[11].versos[3] = _("Acaso as tuas jactâncias farão calar os homens? e zombarás tu sem que ninguém te envergonhe?");
    b->dados[JO].capitulos[11].versos[4] = _("Pois dizes: A minha doutrina é pura, e limpo sou aos teus olhos.");
    b->dados[JO].capitulos[11].versos[5] = _("Mas, na verdade, oxalá que Deus falasse e abrisse os seus lábios contra ti,");
    b->dados[JO].capitulos[11].versos[6] = _("e te fizesse saber os segredos da sabedoria, pois é multiforme o seu entendimento; sabe, pois, que Deus exige de ti menos do que merece a tua iniqüidade.");
    b->dados[JO].capitulos[11].versos[7] = _("Poderás descobrir as coisas profundas de Deus, ou descobrir perfeitamente o Todo-Poderoso?");
    b->dados[JO].capitulos[11].versos[8] = _("Como as alturas do céu é a sua sabedoria; que poderás tu fazer? Mais profunda é ela do que o Seol; que poderás tu saber?");
    b->dados[JO].capitulos[11].versos[9] = _("Mais comprida é a sua medida do que a terra, e mais larga do que o mar.");
    b->dados[JO].capitulos[11].versos[10] = _("Se ele passar e prender alguém, e chamar a juízo, quem o poderá impedir?");
    b->dados[JO].capitulos[11].versos[11] = _("Pois ele conhece os homens vãos; e quando vê a iniqüidade, não atentará para ela?");
    b->dados[JO].capitulos[11].versos[12] = _("Mas o homem vão adquirirá entendimento, quando a cria do asno montês nascer homem.");
    b->dados[JO].capitulos[11].versos[13] = _("Se tu preparares o teu coração, e estenderes as mãos para ele;");
    b->dados[JO].capitulos[11].versos[14] = _("se há iniqüidade na tua mão, lança-a para longe de ti, e não deixes a perversidade habitar nas tuas tendas;");
    b->dados[JO].capitulos[11].versos[15] = _("então levantarás o teu rosto sem mácula, e estarás firme, e não temerás.");
    b->dados[JO].capitulos[11].versos[16] = _("Pois tu te esquecerás da tua miséria; apenas te lembrarás dela como das águas que já passaram.");
    b->dados[JO].capitulos[11].versos[17] = _("E a tua vida será mais clara do que o meio-dia; a escuridão dela será como a alva.");
    b->dados[JO].capitulos[11].versos[18] = _("E terás confiança, porque haverá esperança; olharás ao redor de ti e repousarás seguro.");
    b->dados[JO].capitulos[11].versos[19] = _("Deitar-te-ás, e ninguém te amedrontará; muitos procurarão obter o teu favor.");
    b->dados[JO].capitulos[11].versos[20] = _("Mas os olhos dos ímpios desfalecerão, e para eles não haverá refúgio; a sua esperança será o expirar.");

    b->dados[JO].capitulos[12].versos[1] = _("Então Jó respondeu, dizendo:");
    b->dados[JO].capitulos[12].versos[2] = _("Sem dúvida vós sois o povo, e convosco morrerá a sabedoria.");
    b->dados[JO].capitulos[12].versos[3] = _("Mas eu tenho entendimento como, vos; eu não vos sou inferior. Quem não sabe tais coisas como essas?");
    b->dados[JO].capitulos[12].versos[4] = _("Sou motivo de riso para os meus amigos; eu, que invocava a Deus, e ele me respondia: o justo e reto servindo de irrisão!");
    b->dados[JO].capitulos[12].versos[5] = _("No pensamento de quem está seguro há desprezo para a desgraça; ela está preparada para aquele cujos pés resvalam.");
    b->dados[JO].capitulos[12].versos[6] = _("As tendas dos assoladores têm descanso, e os que provocam a Deus estão seguros; os que trazem o seu deus na mão!");
    b->dados[JO].capitulos[12].versos[7] = _("Mas, pergunta agora às alimárias, e elas te ensinarão; e às aves do céu, e elas te farão saber;");
    b->dados[JO].capitulos[12].versos[8] = _("ou fala com a terra, e ela te ensinará; até os peixes o mar to declararão.");
    b->dados[JO].capitulos[12].versos[9] = _("Qual dentre todas estas coisas não sabe que a mão do Senhor fez isto?");
    b->dados[JO].capitulos[12].versos[10] = _("Na sua mão está a vida de todo ser vivente, e o espírito de todo o gênero humano.");
    b->dados[JO].capitulos[12].versos[11] = _("Porventura o ouvido não prova as palavras, como o paladar prova o alimento?");
    b->dados[JO].capitulos[12].versos[12] = _("Com os anciãos está a sabedoria, e na longura de dias o entendimento.");
    b->dados[JO].capitulos[12].versos[13] = _("Com Deus está a sabedoria e a força; ele tem conselho e entendimento.");
    b->dados[JO].capitulos[12].versos[14] = _("Eis que ele derriba, e não se pode reedificar; ele encerra na prisão, e não se pode abrir.");
    b->dados[JO].capitulos[12].versos[15] = _("Ele retém as águas, e elas secam; solta-as, e elas inundam a terra.");
    b->dados[JO].capitulos[12].versos[16] = _("Com ele está a força e a sabedoria; são dele o enganado e o enganador.");
    b->dados[JO].capitulos[12].versos[17] = _("Aos conselheiros leva despojados, e aos juízes faz desvairar.");
    b->dados[JO].capitulos[12].versos[18] = _("Solta o cinto dos reis, e lhes ata uma corda aos lombos.");
    b->dados[JO].capitulos[12].versos[19] = _("Aos sacerdotes leva despojados, e aos poderosos transtorna.");
    b->dados[JO].capitulos[12].versos[20] = _("Aos que são dignos da confiança emudece, e tira aos anciãos o discernimento.");
    b->dados[JO].capitulos[12].versos[21] = _("Derrama desprezo sobre os príncipes, e afrouxa o cinto dos fortes.");
    b->dados[JO].capitulos[12].versos[22] = _("Das trevas descobre coisas profundas, e traz para a luz a sombra da morte.");
    b->dados[JO].capitulos[12].versos[23] = _("Multiplica as nações e as faz perecer; alarga as fronteiras das nações, e as leva cativas.");
    b->dados[JO].capitulos[12].versos[24] = _("Tira o entendimento aos chefes do povo da terra, e os faz vaguear pelos desertos, sem caminho.");
    b->dados[JO].capitulos[12].versos[25] = _("Eles andam nas trevas às apalpadelas, sem luz, e ele os faz cambalear como um ébrio.");

    b->dados[JO].capitulos[13].versos[1] = _("Eis que os meus olhos viram tudo isto, e os meus ouvidos o ouviram e entenderam.");
    b->dados[JO].capitulos[13].versos[2] = _("O que vós sabeis também eu o sei; não vos sou inferior.");
    b->dados[JO].capitulos[13].versos[3] = _("Mas eu falarei ao Todo-Poderoso, e quero defender-me perante Deus.");
    b->dados[JO].capitulos[13].versos[4] = _("Vós, porém, sois forjadores de mentiras, e vós todos, médicos que não valem nada.");
    b->dados[JO].capitulos[13].versos[5] = _("Oxalá vos calásseis de todo, pois assim passaríeis por sábios.");
    b->dados[JO].capitulos[13].versos[6] = _("Ouvi agora a minha defesa, e escutai os argumentos dos meus lábios.");
    b->dados[JO].capitulos[13].versos[7] = _("Falareis falsamente por Deus, e por ele proferireis mentiras?");
    b->dados[JO].capitulos[13].versos[8] = _("Fareis aceitação da sua pessoa? Contendereis a favor de Deus?");
    b->dados[JO].capitulos[13].versos[9] = _("Ser-vos-ia bom, se ele vos esquadrinhasse? Ou zombareis dele, como quem zomba de um homem?");
    b->dados[JO].capitulos[13].versos[10] = _("Certamente vos repreenderá, se em oculto vos deixardes levar de respeitos humanos.");
    b->dados[JO].capitulos[13].versos[11] = _("Não vos amedrontará a sua majestade? E não cairá sobre vós o seu terror?");
    b->dados[JO].capitulos[13].versos[12] = _("As vossas máximas são provérbios de cinza; as vossas defesas são torres de barro.");
    b->dados[JO].capitulos[13].versos[13] = _("Calai-vos perante mim, para que eu fale, e venha sobre mim o que vier.");
    b->dados[JO].capitulos[13].versos[14] = _("Tomarei a minha carne entre os meus dentes, e porei a minha vida na minha mão.");
    b->dados[JO].capitulos[13].versos[15] = _("Eis que ele me matará; não tenho esperança; contudo defenderei os meus caminhos diante dele.");
    b->dados[JO].capitulos[13].versos[16] = _("Também isso será a minha salvação, pois o ímpio não virá perante ele.");
    b->dados[JO].capitulos[13].versos[17] = _("Ouvi atentamente as minhas palavras, e chegue aos vossos ouvidos a minha declaração.");
    b->dados[JO].capitulos[13].versos[18] = _("Eis que já pus em ordem a minha causa, e sei que serei achado justo:");
    b->dados[JO].capitulos[13].versos[19] = _("Quem é o que contenderá comigo? Pois então me calaria e renderia o espírito.");
    b->dados[JO].capitulos[13].versos[20] = _("Concede-me somente duas coisas; então não me esconderei do teu rosto:");
    b->dados[JO].capitulos[13].versos[21] = _("desvia a tua mão rara longe de mim, e não me amedronte o teu terror.");
    b->dados[JO].capitulos[13].versos[22] = _("Então chama tu, e eu responderei; ou eu falarei, e me responde tu.");
    b->dados[JO].capitulos[13].versos[23] = _("Quantas iniqüidades e pecados tenho eu? Faze-me saber a minha transgressão e o meu pecado.");
    b->dados[JO].capitulos[13].versos[24] = _("Por que escondes o teu rosto, e me tens por teu inimigo?");
    b->dados[JO].capitulos[13].versos[25] = _("Acossarás uma folha arrebatada pelo vento? E perseguirás o restolho seco?");
    b->dados[JO].capitulos[13].versos[26] = _("Pois escreves contra mim coisas amargas, e me fazes herdar os erros da minha mocidade;");
    b->dados[JO].capitulos[13].versos[27] = _("também pões no tronco os meus pés, e observas todos os meus caminhos, e marcas um termo ao redor dos meus pés,");
    b->dados[JO].capitulos[13].versos[28] = _("apesar de eu ser como uma coisa podre que se consome, e como um vestido, ao qual rói a traça.");

    b->dados[JO].capitulos[14].versos[1] = _("O homem, nascido da mulher, é de poucos dias e cheio de inquietação.");
    b->dados[JO].capitulos[14].versos[2] = _("Nasce como a flor, e murcha; foge também como a sombra, e não permanece.");
    b->dados[JO].capitulos[14].versos[3] = _("Sobre esse tal abres os teus olhos, e a mim me fazes entrar em juízo contigo?");
    b->dados[JO].capitulos[14].versos[4] = _("Quem do imundo tirará o puro? Ninguém.");
    b->dados[JO].capitulos[14].versos[5] = _("Visto que os seus dias estão determinados, contigo está o número dos seus meses; tu lhe puseste limites, e ele não poderá passar além deles.");
    b->dados[JO].capitulos[14].versos[6] = _("Desvia dele o teu rosto, para que ele descanse e, como o jornaleiro, tenha contentamento no seu dia.");
    b->dados[JO].capitulos[14].versos[7] = _("Porque há esperança para a árvore, que, se for cortada, ainda torne a brotar, e que não cessem os seus renovos.");
    b->dados[JO].capitulos[14].versos[8] = _("Ainda que envelheça a sua raiz na terra, e morra o seu tronco no pó,");
    b->dados[JO].capitulos[14].versos[9] = _("contudo ao cheiro das águas brotará, e lançará ramos como uma planta nova.");
    b->dados[JO].capitulos[14].versos[10] = _("O homem, porém, morre e se desfaz; sim, rende o homem o espírito, e então onde está?");
    b->dados[JO].capitulos[14].versos[11] = _("Como as águas se retiram de um lago, e um rio se esgota e seca,");
    b->dados[JO].capitulos[14].versos[12] = _("assim o homem se deita, e não se levanta; até que não haja mais céus não acordará nem será despertado de seu sono.");
    b->dados[JO].capitulos[14].versos[13] = _("Oxalá me escondesses no Seol, e me ocultasses até que a tua ira tenha passado; que me determinasses um tempo, e te lembrasses de mim!");
    b->dados[JO].capitulos[14].versos[14] = _("Morrendo o homem, acaso tornará a viver? Todos os dias da minha lida esperaria eu, até que viesse a minha mudança.");
    b->dados[JO].capitulos[14].versos[15] = _("Chamar-me-ias, e eu te responderia; almejarias a obra de tuas mãos.");
    b->dados[JO].capitulos[14].versos[16] = _("Então contarias os meus passos; não estarias a vigiar sobre o meu pecado;");
    b->dados[JO].capitulos[14].versos[17] = _("a minha transgressão estaria selada num saco, e ocultarias a minha iniqüidade.");
    b->dados[JO].capitulos[14].versos[18] = _("Mas, na verdade, a montanha cai e se desfaz, e a rocha se remove do seu lugar.");
    b->dados[JO].capitulos[14].versos[19] = _("As águas gastam as pedras; as enchentes arrebatam o solo; assim tu fazes perecer a esperança do homem.");
    b->dados[JO].capitulos[14].versos[20] = _("Prevaleces para sempre contra ele, e ele passa; mudas o seu rosto e o despedes.");
    b->dados[JO].capitulos[14].versos[21] = _("Os seus filhos recebem honras, sem que ele o saiba; são humilhados sem que ele o perceba.");
    b->dados[JO].capitulos[14].versos[22] = _("Sente as dores do seu próprio corpo somente, e só por si mesmo lamenta.");

    b->dados[JO].capitulos[15].versos[1] = _("Então respondeu Elifaz, o temanita:");
    b->dados[JO].capitulos[15].versos[2] = _("Porventura responderá o sábio com ciência de vento? E encherá do vento oriental o seu ventre,");
    b->dados[JO].capitulos[15].versos[3] = _("argüindo com palavras que de nada servem, ou com razões com que ele nada aproveita?");
    b->dados[JO].capitulos[15].versos[4] = _("Na verdade tu destróis a reverência, e impedes a meditação diante de Deus.");
    b->dados[JO].capitulos[15].versos[5] = _("Pois a tua iniqüidade ensina a tua boca, e escolhes a língua dos astutos.");
    b->dados[JO].capitulos[15].versos[6] = _("A tua própria boca te condena, e não eu; e os teus lábios testificam contra ti.");
    b->dados[JO].capitulos[15].versos[7] = _("És tu o primeiro homem que nasceu? Ou foste dado à luz antes dos outeiros?");
    b->dados[JO].capitulos[15].versos[8] = _("Ou ouviste o secreto conselho de Deus? E a ti só reservas a sabedoria?");
    b->dados[JO].capitulos[15].versos[9] = _("Que sabes tu, que nós não saibamos; que entendes, que não haja em nós?");
    b->dados[JO].capitulos[15].versos[10] = _("Conosco estão os encanecidos e idosos, mais idosos do que teu pai.");
    b->dados[JO].capitulos[15].versos[11] = _("Porventura fazes pouco caso das consolações de Deus, ou da palavra que te trata benignamente?");
    b->dados[JO].capitulos[15].versos[12] = _("Por que te arrebata o teu coração, e por que flamejam os teus olhos,");
    b->dados[JO].capitulos[15].versos[13] = _("de modo que voltas contra Deus o teu espírito, e deixas sair tais palavras da tua boca?");
    b->dados[JO].capitulos[15].versos[14] = _("Que é o homem, para que seja puro? E o que nasce da mulher, para que fique justo?");
    b->dados[JO].capitulos[15].versos[15] = _("Eis que Deus não confia nos seus santos, e nem o céu é puro aos seus olhos;");
    b->dados[JO].capitulos[15].versos[16] = _("quanto menos o homem abominável e corrupto, que bebe a iniqüidade como a água?");
    b->dados[JO].capitulos[15].versos[17] = _("Escuta-me e to mostrarei; contar-te-ei o que tenho visto");
    b->dados[JO].capitulos[15].versos[18] = _("{o que os sábios têm anunciado e seus pais não o ocultaram;");
    b->dados[JO].capitulos[15].versos[19] = _("aos quais somente era dada a terra, não havendo estranho algum passado por entre eles};");
    b->dados[JO].capitulos[15].versos[20] = _("Todos os dias passa o ímpio em angústia, sim, todos os anos que estão reservados para o opressor.");
    b->dados[JO].capitulos[15].versos[21] = _("O sonido de terrores está nos seus ouvidos; na prosperidade lhe sobrevém o assolador.");
    b->dados[JO].capitulos[15].versos[22] = _("Ele não crê que tornará das trevas, mas que o espera a espada.");
    b->dados[JO].capitulos[15].versos[23] = _("Anda vagueando em busca de pão, dizendo: Onde está? Bem sabe que o dia das trevas lhe está perto, à mão.");
    b->dados[JO].capitulos[15].versos[24] = _("Amedrontam-no a angústia e a tribulação; prevalecem contra ele, como um rei preparado para a peleja.");
    b->dados[JO].capitulos[15].versos[25] = _("Porque estendeu a sua mão contra Deus, e contra o Todo-Poderoso se porta com soberba;");
    b->dados[JO].capitulos[15].versos[26] = _("arremete contra ele com dura cerviz, e com as saliências do seu escudo;");
    b->dados[JO].capitulos[15].versos[27] = _("porquanto cobriu o seu rosto com a sua gordura, e criou carne gorda nas ilhargas;");
    b->dados[JO].capitulos[15].versos[28] = _("e habitou em cidades assoladas, em casas em que ninguém deveria morar, que estavam a ponto de tornar-se em montões de ruínas;");
    b->dados[JO].capitulos[15].versos[29] = _("não se enriquecerá, nem subsistirá a sua fazenda, nem se estenderão pela terra as suas possessões.");
    b->dados[JO].capitulos[15].versos[30] = _("Não escapará das trevas; a chama do fogo secará os seus ramos, e ao sopro da boca de Deus desaparecerá.");
    b->dados[JO].capitulos[15].versos[31] = _("Não confie na vaidade, enganando-se a si mesmo; pois a vaidade será a sua recompensa.");
    b->dados[JO].capitulos[15].versos[32] = _("Antes do seu dia se cumprirá, e o seu ramo não reverdecerá.");
    b->dados[JO].capitulos[15].versos[33] = _("Sacudirá as suas uvas verdes, como a vide, e deixará cair a sua flor como a oliveira.");
    b->dados[JO].capitulos[15].versos[34] = _("Pois a assembléia dos ímpios é estéril, e o fogo consumirá as tendas do suborno.");
    b->dados[JO].capitulos[15].versos[35] = _("Concebem a malícia, e dão à luz a iniqüidade, e o seu coração prepara enganos.");

    b->dados[JO].capitulos[16].versos[1] = _("Então Jó respondeu, dizendo:");
    b->dados[JO].capitulos[16].versos[2] = _("Tenho ouvido muitas coisas como essas; todos vós sois consoladores molestos.");
    b->dados[JO].capitulos[16].versos[3] = _("Não terão fim essas palavras de vento? Ou que é o que te provoca, para assim responderes?");
    b->dados[JO].capitulos[16].versos[4] = _("Eu também poderia falar como vós falais, se vós estivésseis em meu lugar; eu poderia amontoar palavras contra vós, e contra vós menear a minha cabeça;");
    b->dados[JO].capitulos[16].versos[5] = _("poderia fortalecer-vos com a minha boca, e a consolação dos meus lábios poderia mitigar a vossa dor.");
    b->dados[JO].capitulos[16].versos[6] = _("Ainda que eu fale, a minha dor não se mitiga; e embora me cale, qual é o meu alívio?");
    b->dados[JO].capitulos[16].versos[7] = _("Mas agora, ó Deus, me deixaste exausto; assolaste toda a minha companhia.");
    b->dados[JO].capitulos[16].versos[8] = _("Tu me emagreceste, e isso constitui uma testemunha contra mim; contra mim se levanta a minha magreza, e o meu rosto testifica contra mim.");
    b->dados[JO].capitulos[16].versos[9] = _("Na sua ira ele me despedaçou, e me perseguiu; rangeu os dentes contra mim; o meu adversário aguça os seus olhos contra mim.");
    b->dados[JO].capitulos[16].versos[10] = _("Os homens abrem contra mim a boca; com desprezo me ferem nas faces, e contra mim se ajuntam à uma.");
    b->dados[JO].capitulos[16].versos[11] = _("Deus me entrega ao ímpio, nas mãos dos iníquos me faz cair.");
    b->dados[JO].capitulos[16].versos[12] = _("Descansado estava eu, e ele me quebrantou; e pegou-me pelo pescoço, e me despedaçou; colocou-me por seu alvo;");
    b->dados[JO].capitulos[16].versos[13] = _("cercam-me os seus flecheiros. Atravessa-me os rins, e não me poupa; derrama o meu fel pela terra.");
    b->dados[JO].capitulos[16].versos[14] = _("Quebranta-me com golpe sobre golpe; arremete contra mim como um guerreiro.");
    b->dados[JO].capitulos[16].versos[15] = _("Sobre a minha pele cosi saco, e deitei a minha glória no pó.");
    b->dados[JO].capitulos[16].versos[16] = _("O meu rosto todo está inflamado de chorar, e há sombras escuras sobre as minhas pálpebras,");
    b->dados[JO].capitulos[16].versos[17] = _("embora não haja violência nas minhas mãos, e seja pura a minha oração.");
    b->dados[JO].capitulos[16].versos[18] = _("Ó terra, não cubras o meu sangue, e não haja lugar em que seja abafado o meu clamor!");
    b->dados[JO].capitulos[16].versos[19] = _("Eis que agora mesmo a minha testemunha está no céu, e o meu fiador nas alturas.");
    b->dados[JO].capitulos[16].versos[20] = _("Os meus amigos zombam de mim; mas os meus olhos se desfazem em lágrimas diante de Deus,");
    b->dados[JO].capitulos[16].versos[21] = _("para que ele defenda o direito que o homem tem diante de Deus e o que o filho do homem tem perante, o seu próximo.");
    b->dados[JO].capitulos[16].versos[22] = _("Pois quando houver decorrido poucos anos, eu seguirei o caminho por onde não tornarei.");

    b->dados[JO].capitulos[17].versos[1] = _("O meu espírito está quebrantado, os meus dias se extinguem, a sepultura me está preparada!");
    b->dados[JO].capitulos[17].versos[2] = _("Deveras estou cercado de zombadores, e os meus olhos contemplam a sua provocação!");
    b->dados[JO].capitulos[17].versos[3] = _("Dá-me, peço-te, um penhor, e sê o meu fiador para contigo; quem mais há que me dê a mão?");
    b->dados[JO].capitulos[17].versos[4] = _("Porque aos seus corações encobriste o entendimento, pelo que não os exaltarás.");
    b->dados[JO].capitulos[17].versos[5] = _("Quem entrega os seus amigos como presa, os olhos de seus filhos desfalecerão.");
    b->dados[JO].capitulos[17].versos[6] = _("Mas a mim me pôs por motejo dos povos; tornei-me como aquele em cujo rosto se cospe.");
    b->dados[JO].capitulos[17].versos[7] = _("De mágoa se escureceram os meus olhos, e todos os meus membros são como a sombra.");
    b->dados[JO].capitulos[17].versos[8] = _("Os retos pasmam disso, e o inocente se levanta contra o ímpio.");
    b->dados[JO].capitulos[17].versos[9] = _("Contudo o justo prossegue no seu caminho e o que tem mãos puras vai crescendo em força.");
    b->dados[JO].capitulos[17].versos[10] = _("Mas tornai vós todos, e vinde, e sábio nenhum acharei entre vós.");
    b->dados[JO].capitulos[17].versos[11] = _("Os meus dias passaram, malograram-se os meus propósitos, as aspirações do meu coração.");
    b->dados[JO].capitulos[17].versos[12] = _("Trocam a noite em dia; dizem que a luz está perto das trevas.");
    b->dados[JO].capitulos[17].versos[13] = _("Se eu olhar o Seol como a minha casa, se nas trevas estender a minha cama,");
    b->dados[JO].capitulos[17].versos[14] = _("se eu clamar à cova: Tu és meu pai; e aos vermes: Vós sois minha mãe e minha irmã;");
    b->dados[JO].capitulos[17].versos[15] = _("onde está então a minha esperança? Sim, a minha esperança, quem a poderá ver?");
    b->dados[JO].capitulos[17].versos[16] = _("Acaso descerá comigo até os ferrolhos do Seol? Descansaremos juntos no pó?");

    b->dados[JO].capitulos[18].versos[1] = _("Então respondeu Bildade, o suíta:");
    b->dados[JO].capitulos[18].versos[2] = _("Até quando estareis à procura de palavras? considerai bem, e então falaremos.");
    b->dados[JO].capitulos[18].versos[3] = _("Por que somos tratados como gado, e como estultos aos vossos olhos?");
    b->dados[JO].capitulos[18].versos[4] = _("Oh tu, que te despedaças na tua ira, acaso por amor de ti será abandonada a terra, ou será a rocha removida do seu lugar?");
    b->dados[JO].capitulos[18].versos[5] = _("Na verdade, a luz do ímpio se apagará, e não resplandecerá a chama do seu fogo.");
    b->dados[JO].capitulos[18].versos[6] = _("A luz se escurecerá na sua tenda, e a lâmpada que está sobre ele se apagará.");
    b->dados[JO].capitulos[18].versos[7] = _("Os seus passos firmes se estreitarão, e o seu próprio conselho o derribará.");
    b->dados[JO].capitulos[18].versos[8] = _("Pois por seus próprios pés é ele lançado na rede, e pisa nos laços armados.");
    b->dados[JO].capitulos[18].versos[9] = _("A armadilha o apanha pelo calcanhar, e o laço o prende;");
    b->dados[JO].capitulos[18].versos[10] = _("a corda do mesmo está-lhe escondida na terra, e uma armadilha na vereda.");
    b->dados[JO].capitulos[18].versos[11] = _("Terrores o amedrontam de todos os lados, e de perto lhe perseguem os pés.");
    b->dados[JO].capitulos[18].versos[12] = _("O seu vigor é diminuído pela fome, e a destruição está pronta ao seu lado.");
    b->dados[JO].capitulos[18].versos[13] = _("São devorados os membros do seu corpo; sim, o primogênito da morte devora os seus membros.");
    b->dados[JO].capitulos[18].versos[14] = _("Arrancado da sua tenda, em que confiava, é levado ao rei dos terrores.");
    b->dados[JO].capitulos[18].versos[15] = _("Na sua tenda habita o que não lhe pertence; espalha-se enxofre sobre a sua habitação.");
    b->dados[JO].capitulos[18].versos[16] = _("Por baixo se secam as suas raízes, e por cima são cortados os seus ramos.");
    b->dados[JO].capitulos[18].versos[17] = _("A sua memória perece da terra, e pelas praças não tem nome.");
    b->dados[JO].capitulos[18].versos[18] = _("É lançado da luz para as trevas, e afugentado do mundo.");
    b->dados[JO].capitulos[18].versos[19] = _("Não tem filho nem neto entre o seu povo, e descendente nenhum lhe ficará nas moradas.");
    b->dados[JO].capitulos[18].versos[20] = _("Do seu dia pasmam os do ocidente, assim como os do oriente ficam sobressaltados de horror.");
    b->dados[JO].capitulos[18].versos[21] = _("Tais são, na verdade, as moradas do, ímpio, e tal é o lugar daquele que não conhece a Deus.");

    b->dados[JO].capitulos[19].versos[1] = _("Então Jó respondeu:");
    b->dados[JO].capitulos[19].versos[2] = _("Até quando afligireis a minha alma, e me atormentareis com palavras?");
    b->dados[JO].capitulos[19].versos[3] = _("Já dez vezes me haveis humilhado; não vos envergonhais de me maltratardes?");
    b->dados[JO].capitulos[19].versos[4] = _("Embora haja eu, na verdade, errado, comigo fica o meu erro.");
    b->dados[JO].capitulos[19].versos[5] = _("Se deveras vos quereis engrandecer contra mim, e me incriminar pelo meu opróbrio,");
    b->dados[JO].capitulos[19].versos[6] = _("sabei então que Deus é o que transtornou a minha causa, e com a sua rede me cercou.");
    b->dados[JO].capitulos[19].versos[7] = _("Eis que clamo: Violência! mas não sou ouvido; grito: Socorro! mas não há justiça.");
    b->dados[JO].capitulos[19].versos[8] = _("com muros fechou ele o meu caminho, de modo que não posso passar; e pôs trevas nas minhas veredas.");
    b->dados[JO].capitulos[19].versos[9] = _("Da minha honra me despojou, e tirou-me da cabeça a coroa.");
    b->dados[JO].capitulos[19].versos[10] = _("Quebrou-me de todos os lados, e eu me vou; arrancou a minha esperança, como a, uma árvore.");
    b->dados[JO].capitulos[19].versos[11] = _("Acende contra mim a sua ira, e me considera como um de seus adversários.");
    b->dados[JO].capitulos[19].versos[12] = _("Juntas as suas tropas avançam, levantam contra mim o seu caminho, e se acampam ao redor da minha tenda.");
    b->dados[JO].capitulos[19].versos[13] = _("Ele pôs longe de mim os meus irmãos, e os que me conhecem tornaram-se estranhos para mim.");
    b->dados[JO].capitulos[19].versos[14] = _("Os meus parentes se afastam, e os meus conhecidos se esquecem de, mim.");
    b->dados[JO].capitulos[19].versos[15] = _("Os meus domésticos e as minhas servas me têm por estranho; vim a ser um estrangeiro aos seus olhos.");
    b->dados[JO].capitulos[19].versos[16] = _("Chamo ao meu criado, e ele não me responde; tenho que suplicar-lhe com a minha boca.");
    b->dados[JO].capitulos[19].versos[17] = _("O meu hálito é intolerável à minha mulher; sou repugnante aos filhos de minha mãe.");
    b->dados[JO].capitulos[19].versos[18] = _("Até os pequeninos me desprezam; quando me levanto, falam contra mim.");
    b->dados[JO].capitulos[19].versos[19] = _("Todos os meus amigos íntimos me abominam, e até os que eu amava se tornaram contra mim.");
    b->dados[JO].capitulos[19].versos[20] = _("Os meus ossos se apegam à minha pele e à minha carne, e só escapei com a pele dos meus dentes.");
    b->dados[JO].capitulos[19].versos[21] = _("Compadecei-vos de mim, amigos meus; compadecei-vos de mim; pois a mão de Deus me tocou.");
    b->dados[JO].capitulos[19].versos[22] = _("Por que me perseguis assim como Deus, e da minha carne não vos fartais?");
    b->dados[JO].capitulos[19].versos[23] = _("Oxalá que as minhas palavras fossem escritas! Oxalá que fossem gravadas num livro!");
    b->dados[JO].capitulos[19].versos[24] = _("Que, com pena de ferro, e com chumbo, fossem para sempre esculpidas na rocha!");
    b->dados[JO].capitulos[19].versos[25] = _("Pois eu sei que o meu Redentor vive, e que por fim se levantará sobre a terra.");
    b->dados[JO].capitulos[19].versos[26] = _("E depois de consumida esta minha pele, então fora da minha carne verei a Deus;");
    b->dados[JO].capitulos[19].versos[27] = _("vê-lo-ei ao meu lado, e os meus olhos o contemplarão, e não mais como adversário. O meu coração desfalece dentro de mim!");
    b->dados[JO].capitulos[19].versos[28] = _("Se disserdes: Como o havemos de perseguir! e que a causa deste mal se acha em mim,");
    b->dados[JO].capitulos[19].versos[29] = _("temei vós a espada; porque o furor traz os castigos da espada, para saberdes que há um juízo.");

    b->dados[JO].capitulos[20].versos[1] = _("Então respondeu Zofar, o naamatita:");
    b->dados[JO].capitulos[20].versos[2] = _("Ora, os meus pensamentos me fazem responder, e por isso eu me apresso.");
    b->dados[JO].capitulos[20].versos[3] = _("Estou ouvindo a tua repreensão, que me envergonha, mas o espírito do meu entendimento responde por mim.");
    b->dados[JO].capitulos[20].versos[4] = _("Não sabes tu que desde a antigüidade, desde que o homem foi posto sobre a terra,");
    b->dados[JO].capitulos[20].versos[5] = _("o triunfo dos iníquos é breve, e a alegria dos ímpios é apenas dum momento?");
    b->dados[JO].capitulos[20].versos[6] = _("Ainda que a sua exaltação suba até o céu, e a sua cabeça chegue até as nuvens,");
    b->dados[JO].capitulos[20].versos[7] = _("contudo, como o seu próprio esterco, perecerá para sempre; e os que o viam perguntarão: Onde está?");
    b->dados[JO].capitulos[20].versos[8] = _("Dissipar-se-á como um sonho, e não será achado; será afugentado qual uma visão da noite.");
    b->dados[JO].capitulos[20].versos[9] = _("Os olhos que o viam não o verão mais, nem o seu lugar o contemplará mais.");
    b->dados[JO].capitulos[20].versos[10] = _("Os seus filhos procurarão o favor dos pobres, e as suas mãos restituirão os seus lucros ilícitos.");
    b->dados[JO].capitulos[20].versos[11] = _("Os seus ossos estão cheios do vigor da sua juventude, mas este se deitará com ele no pó.");
    b->dados[JO].capitulos[20].versos[12] = _("Ainda que o mal lhe seja doce na boca, ainda que ele o esconda debaixo da sua língua,");
    b->dados[JO].capitulos[20].versos[13] = _("ainda que não o queira largar, antes o retenha na sua boca,");
    b->dados[JO].capitulos[20].versos[14] = _("contudo a sua comida se transforma nas suas entranhas; dentro dele se torna em fel de áspides.");
    b->dados[JO].capitulos[20].versos[15] = _("Engoliu riquezas, mas vomitá-las-á; do ventre dele Deus as lançará.");
    b->dados[JO].capitulos[20].versos[16] = _("Veneno de áspides sorverá, língua de víbora o matará.");
    b->dados[JO].capitulos[20].versos[17] = _("Não verá as correntes, os rios e os ribeiros de mel e de manteiga.");
    b->dados[JO].capitulos[20].versos[18] = _("O que adquiriu pelo trabalho, isso restituirá, e não o engolirá; não se regozijará conforme a fazenda que ajuntou.");
    b->dados[JO].capitulos[20].versos[19] = _("Pois que oprimiu e desamparou os pobres, e roubou a casa que não edificou.");
    b->dados[JO].capitulos[20].versos[20] = _("Porquanto não houve limite à sua cobiça, nada salvará daquilo em que se deleita.");
    b->dados[JO].capitulos[20].versos[21] = _("Nada escapou à sua voracidade; pelo que a sua prosperidade não perdurará.");
    b->dados[JO].capitulos[20].versos[22] = _("Na plenitude da sua abastança, estará angustiado; toda a força da miséria virá sobre ele.");
    b->dados[JO].capitulos[20].versos[23] = _("Mesmo estando ele a encher o seu estômago, Deus mandará sobre ele o ardor da sua ira, que fará chover sobre ele quando for comer.");
    b->dados[JO].capitulos[20].versos[24] = _("Ainda que fuja das armas de ferro, o arco de bronze o atravessará.");
    b->dados[JO].capitulos[20].versos[25] = _("Ele arranca do seu corpo a flecha, que sai resplandecente do seu fel; terrores vêm sobre ele.");
    b->dados[JO].capitulos[20].versos[26] = _("Todas as trevas são reservadas paro os seus tesouros; um fogo não assoprado o consumirá, e devorará o que ficar na sua tenda.");
    b->dados[JO].capitulos[20].versos[27] = _("Os céus revelarão a sua iniqüidade, e contra ele a terra se levantará.");
    b->dados[JO].capitulos[20].versos[28] = _("As rendas de sua casa ir-se-ão; no dia da ira de Deus todas se derramarão.");
    b->dados[JO].capitulos[20].versos[29] = _("Esta, da parte de Deus, é a porção do ímpio; esta é a herança que Deus lhe reserva.");

    b->dados[JO].capitulos[21].versos[1] = _("Então Jó respondeu:");
    b->dados[JO].capitulos[21].versos[2] = _("Ouvi atentamente as minhas palavras; seja isto a vossa consolação.");
    b->dados[JO].capitulos[21].versos[3] = _("Sofrei-me, e eu falarei; e, havendo eu falado, zombai.");
    b->dados[JO].capitulos[21].versos[4] = _("É porventura do homem que eu me queixo? Mas, ainda que assim fosse, não teria motivo de me impacientar?");
    b->dados[JO].capitulos[21].versos[5] = _("Olhai para mim, e pasmai, e ponde a mão sobre a boca.");
    b->dados[JO].capitulos[21].versos[6] = _("Quando me lembro disto, me perturbo, e a minha carne estremece de horror.");
    b->dados[JO].capitulos[21].versos[7] = _("Por que razão vivem os ímpios, envelhecem, e ainda se robustecem em poder?");
    b->dados[JO].capitulos[21].versos[8] = _("Os seus filhos se estabelecem à vista deles, e os seus descendentes perante os seus olhos.");
    b->dados[JO].capitulos[21].versos[9] = _("As suas casas estão em paz, sem temor, e a vara de Deus não está sobre eles.");
    b->dados[JO].capitulos[21].versos[10] = _("O seu touro gera, e não falha; pare a sua vaca, e não aborta.");
    b->dados[JO].capitulos[21].versos[11] = _("Eles fazem sair os seus pequeninos, como a um rebanho, e suas crianças andam saltando.");
    b->dados[JO].capitulos[21].versos[12] = _("Levantam a voz, ao som do tamboril e da harpa, e regozijam-se ao som da flauta.");
    b->dados[JO].capitulos[21].versos[13] = _("Na prosperidade passam os seus dias, e num momento descem ao Seol.");
    b->dados[JO].capitulos[21].versos[14] = _("Eles dizem a Deus: retira-te de nós, pois não desejamos ter conhecimento dos teus caminhos.");
    b->dados[JO].capitulos[21].versos[15] = _("Que é o Todo-Poderoso, para que nós o sirvamos? E que nos aproveitará, se lhe fizermos orações?");
    b->dados[JO].capitulos[21].versos[16] = _("Vede, porém, que eles não têm na mão a prosperidade; esteja longe de mim o conselho dos ímpios!");
    b->dados[JO].capitulos[21].versos[17] = _("Quantas vezes sucede que se apague a lâmpada dos ímpios? que lhes sobrevenha a sua destruição? que Deus na sua ira lhes reparta dores?");
    b->dados[JO].capitulos[21].versos[18] = _("que eles sejam como a palha diante do vento, e como a pragana, que o redemoinho arrebata?");
    b->dados[JO].capitulos[21].versos[19] = _("Deus, dizeis vós, reserva a iniqüidade do pai para seus filhos, mas é a ele mesmo que Deus deveria punir, para que o conheça.");
    b->dados[JO].capitulos[21].versos[20] = _("Vejam os seus próprios olhos a sua ruína, e beba ele do furor do Todo-Poderoso.");
    b->dados[JO].capitulos[21].versos[21] = _("Pois, que lhe importa a sua casa depois de morto, quando lhe for cortado o número dos seus meses?");
    b->dados[JO].capitulos[21].versos[22] = _("Acaso se ensinará ciência a Deus, a ele que julga os excelsos?");
    b->dados[JO].capitulos[21].versos[23] = _("Um morre em plena prosperidade, inteiramente sossegado e tranqüilo;");
    b->dados[JO].capitulos[21].versos[24] = _("com os seus baldes cheios de leite, e a medula dos seus ossos umedecida.");
    b->dados[JO].capitulos[21].versos[25] = _("Outro, ao contrário, morre em amargura de alma, não havendo provado do bem.");
    b->dados[JO].capitulos[21].versos[26] = _("Juntamente jazem no pó, e os vermes os cobrem.");
    b->dados[JO].capitulos[21].versos[27] = _("Eis que conheço os vossos pensamentos, e os maus intentos com que me fazeis injustiça.");
    b->dados[JO].capitulos[21].versos[28] = _("Pois dizeis: Onde está a casa do príncipe, e onde a tenda em que morava o ímpio?");
    b->dados[JO].capitulos[21].versos[29] = _("Porventura não perguntastes aos viandantes? e não aceitais o seu testemunho,");
    b->dados[JO].capitulos[21].versos[30] = _("de que o mau é preservado no dia da destruição, e poupado no dia do furor?");
    b->dados[JO].capitulos[21].versos[31] = _("Quem acusará diante dele o seu caminho? e quem lhe dará o pago do que fez?");
    b->dados[JO].capitulos[21].versos[32] = _("Ele é levado para a sepultura, e vigiam-lhe o túmulo.");
    b->dados[JO].capitulos[21].versos[33] = _("Os torrões do vale lhe são doces, e o seguirão todos os homens, como ele o fez aos inumeráveis que o precederam.");
    b->dados[JO].capitulos[21].versos[34] = _("Como, pois, me ofereceis consolações vãs, quando nas vossas respostas só resta falsidade?");

    b->dados[JO].capitulos[22].versos[1] = _("Então respondeu Elifaz, o temanita:");
    b->dados[JO].capitulos[22].versos[2] = _("Pode o homem ser de algum proveito a Deus? Antes a si mesmo é que o prudente será proveitoso.");
    b->dados[JO].capitulos[22].versos[3] = _("Tem o Todo-Poderoso prazer em que tu sejas justo, ou lucro em que tu faças perfeitos os teus caminhos?");
    b->dados[JO].capitulos[22].versos[4] = _("É por causa da tua reverência que te repreende, ou que entra contigo em juízo?");
    b->dados[JO].capitulos[22].versos[5] = _("Não é grande a tua malícia, e sem termo as tuas iniqüidades?");
    b->dados[JO].capitulos[22].versos[6] = _("Pois sem causa tomaste penhores a teus irmãos e aos nus despojaste dos vestidos.");
    b->dados[JO].capitulos[22].versos[7] = _("Não deste ao cansado água a beber, e ao faminto retiveste o pão.");
    b->dados[JO].capitulos[22].versos[8] = _("Mas ao poderoso pertencia a terra, e o homem acatado habitava nela.");
    b->dados[JO].capitulos[22].versos[9] = _("Despediste vazias as viúvas, e os braços dos órfãos foram quebrados.");
    b->dados[JO].capitulos[22].versos[10] = _("Por isso é que estás cercado de laços, e te perturba um pavor repentino,");
    b->dados[JO].capitulos[22].versos[11] = _("ou trevas de modo que nada podes ver, e a inundação de águas te cobre.");
    b->dados[JO].capitulos[22].versos[12] = _("Não está Deus na altura do céu? Olha para as mais altas estrelas, quão elevadas estão!");
    b->dados[JO].capitulos[22].versos[13] = _("E dizes: Que sabe Deus? Pode ele julgar através da escuridão?");
    b->dados[JO].capitulos[22].versos[14] = _("Grossas nuvens o encobrem, de modo que não pode ver; e ele passeia em volta da abóbada do céu.");
    b->dados[JO].capitulos[22].versos[15] = _("Queres seguir a vereda antiga, que pisaram os homens iníquos?");
    b->dados[JO].capitulos[22].versos[16] = _("Os quais foram arrebatados antes do seu tempo; e o seu fundamento se derramou qual um rio.");
    b->dados[JO].capitulos[22].versos[17] = _("Diziam a Deus: retira-te de nós; e ainda: Que é que o Todo-Poderoso nos pode fazer?");
    b->dados[JO].capitulos[22].versos[18] = _("Contudo ele encheu de bens as suas casas. Mas longe de mim estejam os conselhos dos ímpios!");
    b->dados[JO].capitulos[22].versos[19] = _("Os justos o vêem, e se alegram: e os inocentes escarnecem deles,");
    b->dados[JO].capitulos[22].versos[20] = _("dizendo: Na verdade são exterminados os nossos adversários, e o fogo consumiu o que deixaram.");
    b->dados[JO].capitulos[22].versos[21] = _("Apega-te, pois, a Deus, e tem paz, e assim te sobrevirá o bem.");
    b->dados[JO].capitulos[22].versos[22] = _("Aceita, peço-te, a lei da sua boca, e põe as suas palavras no teu coração.");
    b->dados[JO].capitulos[22].versos[23] = _("Se te voltares para o Todo-Poderoso, serás edificado; se lançares a iniqüidade longe da tua tenda,");
    b->dados[JO].capitulos[22].versos[24] = _("e deitares o teu tesouro no pó, e o ouro de Ofir entre as pedras dos ribeiros,");
    b->dados[JO].capitulos[22].versos[25] = _("então o Todo-Poderoso será o teu tesouro, e a tua prata preciosa.");
    b->dados[JO].capitulos[22].versos[26] = _("Pois então te deleitarás no Todo-Poderoso, e levantarás o teu rosto para Deus.");
    b->dados[JO].capitulos[22].versos[27] = _("Tu orarás a ele, e ele te ouvirá; e pagarás os teus votos.");
    b->dados[JO].capitulos[22].versos[28] = _("Também determinarás algum negócio, e ser-te-á firme, e a luz brilhará em teus caminhos.");
    b->dados[JO].capitulos[22].versos[29] = _("Quando te abaterem, dirás: haja exaltação! E Deus salvará ao humilde.");
    b->dados[JO].capitulos[22].versos[30] = _("E livrará até o que não é inocente, que será libertado pela pureza de tuas mãos.");

    b->dados[JO].capitulos[23].versos[1] = _("Então Jó respondeu:");
    b->dados[JO].capitulos[23].versos[2] = _("Ainda hoje a minha queixa está em amargura; o peso da mão dele é maior do que o meu gemido.");
    b->dados[JO].capitulos[23].versos[3] = _("Ah, se eu soubesse onde encontrá-lo, e pudesse chegar ao seu tribunal!");
    b->dados[JO].capitulos[23].versos[4] = _("Exporia ante ele a minha causa, e encheria a minha boca de argumentos.");
    b->dados[JO].capitulos[23].versos[5] = _("Saberia as palavras com que ele me respondesse, e entenderia o que me dissesse.");
    b->dados[JO].capitulos[23].versos[6] = _("Acaso contenderia ele comigo segundo a grandeza do seu poder? Não; antes ele me daria ouvidos.");
    b->dados[JO].capitulos[23].versos[7] = _("Ali o reto pleitearia com ele, e eu seria absolvido para sempre por meu Juiz.");
    b->dados[JO].capitulos[23].versos[8] = _("Eis que vou adiante, mas não está ali; volto para trás, e não o percebo;");
    b->dados[JO].capitulos[23].versos[9] = _("procuro-o à esquerda, onde ele opera, mas não o vejo; viro-me para a direita, e não o diviso.");
    b->dados[JO].capitulos[23].versos[10] = _("Mas ele sabe o caminho por que eu ando; provando-me ele, sairei como o ouro.");
    b->dados[JO].capitulos[23].versos[11] = _("Os meus pés se mantiveram nas suas pisadas; guardei o seu caminho, e não me desviei dele.");
    b->dados[JO].capitulos[23].versos[12] = _("Nunca me apartei do preceito dos seus lábios, e escondi no meu peito as palavras da sua boca.");
    b->dados[JO].capitulos[23].versos[13] = _("Mas ele está resolvido; quem então pode desviá-lo? E o que ele quiser, isso fará.");
    b->dados[JO].capitulos[23].versos[14] = _("Pois cumprirá o que está ordenado a meu respeito, e muitas coisas como estas ainda tem consigo.");
    b->dados[JO].capitulos[23].versos[15] = _("Por isso me perturbo diante dele; e quando considero, tenho medo dele.");
    b->dados[JO].capitulos[23].versos[16] = _("Deus macerou o meu coração; o Todo-Poderoso me perturbou.");
    b->dados[JO].capitulos[23].versos[17] = _("Pois não estou desfalecido por causa das trevas, nem porque a escuridão cobre o meu rosto.");

    b->dados[JO].capitulos[24].versos[1] = _("Por que o Todo-Poderoso não designa tempos? e por que os que o conhecem não vêem os seus dias?");
    b->dados[JO].capitulos[24].versos[2] = _("Há os que removem os limites; roubam os rebanhos, e os apascentam.");
    b->dados[JO].capitulos[24].versos[3] = _("Levam o jumento do órfão, tomam em penhor o boi da viúva.");
    b->dados[JO].capitulos[24].versos[4] = _("Desviam do caminho os necessitados; e os oprimidos da terra juntos se escondem.");
    b->dados[JO].capitulos[24].versos[5] = _("Eis que, como jumentos monteses no deserto, saem eles ao seu trabalho, procurando no ermo a presa que lhes sirva de sustento para seus filhos.");
    b->dados[JO].capitulos[24].versos[6] = _("No campo segam o seu pasto, e vindimam a vinha do ímpio.");
    b->dados[JO].capitulos[24].versos[7] = _("Passam a noite nus, sem roupa, não tendo coberta contra o frio.");
    b->dados[JO].capitulos[24].versos[8] = _("Pelas chuvas das montanhas são molhados e, por falta de abrigo, abraçam-se com as rochas.");
    b->dados[JO].capitulos[24].versos[9] = _("Há os que arrancam do peito o órfão, e tomam o penhor do pobre;");
    b->dados[JO].capitulos[24].versos[10] = _("fazem que estes andem nus, sem roupa, e, embora famintos, carreguem os molhos.");
    b->dados[JO].capitulos[24].versos[11] = _("Espremem o azeite dentro dos muros daqueles homens; pisam os seus lagares, e ainda têm sede.");
    b->dados[JO].capitulos[24].versos[12] = _("Dentro das cidades gemem os moribundos, e a alma dos feridos clama; e contudo Deus não considera o seu clamor.");
    b->dados[JO].capitulos[24].versos[13] = _("Há os que se revoltam contra a luz; não conhecem os caminhos dela, e não permanecem nas suas veredas.");
    b->dados[JO].capitulos[24].versos[14] = _("O homicida se levanta de madrugada, mata o pobre e o necessitado, e de noite torna-se ladrão.");
    b->dados[JO].capitulos[24].versos[15] = _("Também os olhos do adúltero aguardam o crepúsculo, dizendo: Ninguém me verá; e disfarça o rosto.");
    b->dados[JO].capitulos[24].versos[16] = _("Nas trevas minam as casas; de dia se conservam encerrados; não conhecem a luz.");
    b->dados[JO].capitulos[24].versos[17] = _("Pois para eles a profunda escuridão é a sua manhã; porque são amigos das trevas espessas.");
    b->dados[JO].capitulos[24].versos[18] = _("São levados ligeiramente sobre a face das águas; maldita é a sua porção sobre a terra; não tornam pelo caminho das vinhas.");
    b->dados[JO].capitulos[24].versos[19] = _("A sequidão e o calor desfazem as, águas da neve; assim faz o Seol aos que pecaram.");
    b->dados[JO].capitulos[24].versos[20] = _("A madre se esquecerá dele; os vermes o comerão gostosamente; não será mais lembrado; e a iniqüidade se quebrará como árvore.");
    b->dados[JO].capitulos[24].versos[21] = _("Ele despoja a estéril que não dá à luz, e não faz bem à viúva.");
    b->dados[JO].capitulos[24].versos[22] = _("Todavia Deus prolonga a vida dos valentes com a sua força; levantam-se quando haviam desesperado da vida.");
    b->dados[JO].capitulos[24].versos[23] = _("Se ele lhes dá descanso, estribam-se, nisso; e os seus olhos estão sobre os caminhos deles.");
    b->dados[JO].capitulos[24].versos[24] = _("Eles se exaltam, mas logo desaparecem; são abatidos, colhidos como os demais, e cortados como as espigas do trigo.");
    b->dados[JO].capitulos[24].versos[25] = _("Se não é assim, quem me desmentirá e desfará as minhas palavras?");

    b->dados[JO].capitulos[25].versos[1] = _("Então respondeu Bildade, o suíta:");
    b->dados[JO].capitulos[25].versos[2] = _("Com Deus estão domínio e temor; ele faz reinar a paz nas suas alturas.");
    b->dados[JO].capitulos[25].versos[3] = _("Acaso têm número os seus exércitos? E sobre quem não se levanta a sua luz?");
    b->dados[JO].capitulos[25].versos[4] = _("Como, pois, pode o homem ser justo diante de Deus, e como pode ser puro aquele que nasce da mulher?");
    b->dados[JO].capitulos[25].versos[5] = _("Eis que até a lua não tem brilho, e as estrelas não são puras aos olhos dele;");
    b->dados[JO].capitulos[25].versos[6] = _("quanto menos o homem, que é um verme, e o filho do homem, que é um vermezinho!");

    b->dados[JO].capitulos[26].versos[1] = _("Então Jó respondeu:");
    b->dados[JO].capitulos[26].versos[2] = _("Como tens ajudado ao que não tem força e sustentado o braço que não tem vigor!");
    b->dados[JO].capitulos[26].versos[3] = _("como tens aconselhado ao que não tem sabedoria, e plenamente tens revelado o verdadeiro conhecimento!");
    b->dados[JO].capitulos[26].versos[4] = _("Para quem proferiste palavras? E de quem é o espírito que saiu de ti?");
    b->dados[JO].capitulos[26].versos[5] = _("Os mortos tremem debaixo das águas, com os que ali habitam.");
    b->dados[JO].capitulos[26].versos[6] = _("O Seol está nu perante Deus, e não há coberta para o Abadom.");
    b->dados[JO].capitulos[26].versos[7] = _("Ele estende o norte sobre o vazio; suspende a terra sobre o nada.");
    b->dados[JO].capitulos[26].versos[8] = _("Prende as águas em suas densas nuvens, e a nuvem não se rasga debaixo delas.");
    b->dados[JO].capitulos[26].versos[9] = _("Encobre a face do seu trono, e sobre ele estende a sua nuvem.");
    b->dados[JO].capitulos[26].versos[10] = _("Marcou um limite circular sobre a superfície das águas, onde a luz e as trevas se confinam.");
    b->dados[JO].capitulos[26].versos[11] = _("As colunas do céu tremem, e se espantam da sua ameaça.");
    b->dados[JO].capitulos[26].versos[12] = _("Com o seu poder fez sossegar o mar, e com o seu entendimento abateu a Raabe.");
    b->dados[JO].capitulos[26].versos[13] = _("Pelo seu sopro ornou o céu; a sua mão traspassou a serpente veloz.");
    b->dados[JO].capitulos[26].versos[14] = _("Eis que essas coisas são apenas as orlas dos seus caminhos; e quão pequeno é o sussurro que dele, ouvimos! Mas o trovão do seu poder, quem o poderá entender?");

    b->dados[JO].capitulos[27].versos[1] = _("E prosseguindo Jó em seu discurso, disse:");
    b->dados[JO].capitulos[27].versos[2] = _("Vive Deus, que me tirou o direito, e o Todo-Poderoso, que me amargurou a alma;");
    b->dados[JO].capitulos[27].versos[3] = _("enquanto em mim houver alento, e o sopro de Deus no meu nariz,");
    b->dados[JO].capitulos[27].versos[4] = _("não falarão os meus lábios iniqüidade, nem a minha língua pronunciará engano.");
    b->dados[JO].capitulos[27].versos[5] = _("Longe de mim que eu vos dê razão; até que eu morra, nunca apartarei de mim a minha integridade.");
    b->dados[JO].capitulos[27].versos[6] = _("À minha justiça me apegarei e não a largarei; o meu coração não reprova dia algum da minha vida.");
    b->dados[JO].capitulos[27].versos[7] = _("Seja como o ímpio o meu inimigo, e como o perverso aquele que se levantar contra mim.");
    b->dados[JO].capitulos[27].versos[8] = _("Pois qual é a esperança do ímpio, quando Deus o cortar, quando Deus lhe arrebatar a alma?");
    b->dados[JO].capitulos[27].versos[9] = _("Acaso Deus lhe ouvirá o clamor, sobrevindo-lhe a tribulação?");
    b->dados[JO].capitulos[27].versos[10] = _("Deleitar-se-á no Todo-Poderoso, ou invocará a Deus em todo o tempo?");
    b->dados[JO].capitulos[27].versos[11] = _("Ensinar-vos-ei acerca do poder de Deus, e não vos encobrirei o que está com o Todo-Poderoso.");
    b->dados[JO].capitulos[27].versos[12] = _("Eis que todos vós já vistes isso; por que, pois, vos entregais completamente à vaidade?");
    b->dados[JO].capitulos[27].versos[13] = _("Esta é da parte de Deus a porção do ímpio, e a herança que os opressores recebem do Todo-Poderoso:");
    b->dados[JO].capitulos[27].versos[14] = _("Se os seus filhos se multiplicarem, será para a espada; e a sua prole não se fartará de pão.");
    b->dados[JO].capitulos[27].versos[15] = _("Os que ficarem dele, pela peste serão sepultados, e as suas viúvas não chorarão.");
    b->dados[JO].capitulos[27].versos[16] = _("Embora amontoe prata como pó, e acumule vestes como barro,");
    b->dados[JO].capitulos[27].versos[17] = _("ele as pode acumular, mas o justo as vestirá, e o inocente repartirá a prata.");
    b->dados[JO].capitulos[27].versos[18] = _("A casa que ele edifica é como a teia da aranha, e como a cabana que o guarda faz.");
    b->dados[JO].capitulos[27].versos[19] = _("Rico se deita, mas não o fará mais; abre os seus olhos, e já se foi a sua riqueza.");
    b->dados[JO].capitulos[27].versos[20] = _("Pavores o alcançam como um dilúvio; de noite o arrebata a tempestade.");
    b->dados[JO].capitulos[27].versos[21] = _("O vento oriental leva-o, e ele se vai; sim, varre-o com ímpeto do seu lugar:");
    b->dados[JO].capitulos[27].versos[22] = _("Pois atira contra ele, e não o poupa, e ele foge precipitadamente do seu poder.");
    b->dados[JO].capitulos[27].versos[23] = _("Bate palmas contra ele, e assobia contra ele do seu lugar.");

    b->dados[JO].capitulos[28].versos[1] = _("Na verdade, há minas donde se extrai a prata, e também lugar onde se refina o ouro:");
    b->dados[JO].capitulos[28].versos[2] = _("O ferro tira-se da terra, e da pedra se funde o cobre.");
    b->dados[JO].capitulos[28].versos[3] = _("Os homens põem termo às trevas, e até os últimos confins exploram as pedras na escuridão e nas trevas mais densas.");
    b->dados[JO].capitulos[28].versos[4] = _("Abrem um poço de mina longe do lugar onde habitam; são esquecidos pelos viajantes, ficando pendentes longe dos homens, e oscilam de um lado para o outro.");
    b->dados[JO].capitulos[28].versos[5] = _("Quanto à terra, dela procede o pão, mas por baixo é revolvida como por fogo.");
    b->dados[JO].capitulos[28].versos[6] = _("As suas pedras são o lugar de safiras, e têm pó de ouro.");
    b->dados[JO].capitulos[28].versos[7] = _("A ave de rapina não conhece essa vereda, e não a viram os olhos do falcão.");
    b->dados[JO].capitulos[28].versos[8] = _("Nunca a pisaram feras altivas, nem o feroz leão passou por ela.");
    b->dados[JO].capitulos[28].versos[9] = _("O homem estende a mão contra a pederneira, e revolve os montes desde as suas raízes.");
    b->dados[JO].capitulos[28].versos[10] = _("Corta canais nas pedras, e os seus olhos descobrem todas as coisas preciosas.");
    b->dados[JO].capitulos[28].versos[11] = _("Ele tapa os veios d'água para que não gotejem; e tira para a luz o que estava escondido.");
    b->dados[JO].capitulos[28].versos[12] = _("Mas onde se achará a sabedoria? E onde está o lugar do entendimento?");
    b->dados[JO].capitulos[28].versos[13] = _("O homem não lhe conhece o caminho; nem se acha ela na terra dos viventes.");
    b->dados[JO].capitulos[28].versos[14] = _("O abismo diz: Não está em mim; e o mar diz: Ela não está comigo.");
    b->dados[JO].capitulos[28].versos[15] = _("Não pode ser comprada com ouro fino, nem a peso de prata se trocará.");
    b->dados[JO].capitulos[28].versos[16] = _("Nem se pode avaliar em ouro fino de Ofir, nem em pedras preciosas de berilo, ou safira.");
    b->dados[JO].capitulos[28].versos[17] = _("Com ela não se pode comparar o ouro ou o vidro; nem se trocara por jóias de ouro fino.");
    b->dados[JO].capitulos[28].versos[18] = _("Não se fará menção de coral nem de cristal; porque a aquisição da sabedoria é melhor que a das pérolas.");
    b->dados[JO].capitulos[28].versos[19] = _("Não se lhe igualará o topázio da Etiópia, nem se pode comprar por ouro puro.");
    b->dados[JO].capitulos[28].versos[20] = _("Donde, pois, vem a sabedoria? Onde está o lugar do entendimento?");
    b->dados[JO].capitulos[28].versos[21] = _("Está encoberta aos olhos de todo vivente, e oculta às aves do céu.");
    b->dados[JO].capitulos[28].versos[22] = _("O Abadom e a morte dizem: Ouvimos com os nossos ouvidos um rumor dela.");
    b->dados[JO].capitulos[28].versos[23] = _("Deus entende o seu caminho, e ele sabe o seu lugar.");
    b->dados[JO].capitulos[28].versos[24] = _("Porque ele perscruta até as extremidades da terra, sim, ele vê tudo o que há debaixo do céu.");
    b->dados[JO].capitulos[28].versos[25] = _("Quando regulou o peso do vento, e fixou a medida das águas;");
    b->dados[JO].capitulos[28].versos[26] = _("quando prescreveu leis para a chuva e caminho para o relâmpago dos trovões;");
    b->dados[JO].capitulos[28].versos[27] = _("então viu a sabedoria e a manifestou; estabeleceu-a, e também a esquadrinhou.");
    b->dados[JO].capitulos[28].versos[28] = _("E disse ao homem: Eis que o temor do Senhor é a sabedoria, e o apartar-se do mal é o entendimento.");

    b->dados[JO].capitulos[29].versos[1] = _("E prosseguindo Jó no seu discurso, disse:");
    b->dados[JO].capitulos[29].versos[2] = _("Ah! quem me dera ser como eu fui nos meses do passado, como nos dias em que Deus me guardava;");
    b->dados[JO].capitulos[29].versos[3] = _("quando a sua lâmpada luzia sobre o minha cabeça, e eu com a sua luz caminhava através das trevas;");
    b->dados[JO].capitulos[29].versos[4] = _("como era nos dias do meu vigor, quando o íntimo favor de Deus estava sobre a minha tenda;");
    b->dados[JO].capitulos[29].versos[5] = _("quando o Todo-Poderoso ainda estava comigo, e os meus filhos em redor de mim;");
    b->dados[JO].capitulos[29].versos[6] = _("quando os meus passos eram banhados em leite, e a rocha me deitava ribeiros de azeite!");
    b->dados[JO].capitulos[29].versos[7] = _("Quando eu saía para a porta da cidade, e na praça preparava a minha cadeira,");
    b->dados[JO].capitulos[29].versos[8] = _("os moços me viam e se escondiam, e os idosos se levantavam e se punham em pé;");
    b->dados[JO].capitulos[29].versos[9] = _("os príncipes continham as suas palavras, e punham a mão sobre a sua boca;");
    b->dados[JO].capitulos[29].versos[10] = _("a voz dos nobres emudecia, e a língua se lhes pegava ao paladar.");
    b->dados[JO].capitulos[29].versos[11] = _("Pois, ouvindo-me algum ouvido, me tinha por bem-aventurado; e vendo-me algum olho, dava testemunho de mim;");
    b->dados[JO].capitulos[29].versos[12] = _("porque eu livrava o miserável que clamava, e o órfão que não tinha quem o socorresse.");
    b->dados[JO].capitulos[29].versos[13] = _("A bênção do que estava a perecer vinha sobre mim, e eu fazia rejubilar-se o coração da viúva.");
    b->dados[JO].capitulos[29].versos[14] = _("vestia-me da retidão, e ela se vestia de mim; como manto e diadema era a minha justiça.");
    b->dados[JO].capitulos[29].versos[15] = _("Fazia-me olhos para o cego, e pés para o coxo;");
    b->dados[JO].capitulos[29].versos[16] = _("dos necessitados era pai, e a causa do que me era desconhecido examinava com diligência.");
    b->dados[JO].capitulos[29].versos[17] = _("E quebrava os caninos do perverso, e arrancava-lhe a presa dentre os dentes.");
    b->dados[JO].capitulos[29].versos[18] = _("Então dizia eu: No meu ninho expirarei, e multiplicarei os meus dias como a areia;");
    b->dados[JO].capitulos[29].versos[19] = _("as minhas raízes se estendem até as águas, e o orvalho fica a noite toda sobre os meus ramos;");
    b->dados[JO].capitulos[29].versos[20] = _("a minha honra se renova em mim, e o meu arco se revigora na minha mão.");
    b->dados[JO].capitulos[29].versos[21] = _("A mim me ouviam e esperavam, e em silêncio atendiam ao meu conselho.");
    b->dados[JO].capitulos[29].versos[22] = _("Depois de eu falar, nada replicavam, e minha palavra destilava sobre eles;");
    b->dados[JO].capitulos[29].versos[23] = _("esperavam-me como à chuva; e abriam a sua boca como à chuva tardia.");
    b->dados[JO].capitulos[29].versos[24] = _("Eu lhes sorria quando não tinham confiança; e não desprezavam a luz do meu rosto;");
    b->dados[JO].capitulos[29].versos[25] = _("eu lhes escolhia o caminho, assentava-me como chefe, e habitava como rei entre as suas tropas, como aquele que consola os aflitos.");

    b->dados[JO].capitulos[30].versos[1] = _("Mas agora zombam de mim os de menos idade do que eu, cujos pais teria eu desdenhado de pôr com os cães do meu rebanho.");
    b->dados[JO].capitulos[30].versos[2] = _("Pois de que me serviria a força das suas mãos, homens nos quais já pereceu o vigor?");
    b->dados[JO].capitulos[30].versos[3] = _("De míngua e fome emagrecem; andam roendo pelo deserto, lugar de ruínas e desolação.");
    b->dados[JO].capitulos[30].versos[4] = _("Apanham malvas junto aos arbustos, e o seu mantimento são as raízes dos zimbros.");
    b->dados[JO].capitulos[30].versos[5] = _("São expulsos do meio dos homens, que gritam atrás deles, como atrás de um ladrão.");
    b->dados[JO].capitulos[30].versos[6] = _("Têm que habitar nos desfiladeiros sombrios, nas cavernas da terra e dos penhascos.");
    b->dados[JO].capitulos[30].versos[7] = _("Bramam entre os arbustos, ajuntam-se debaixo das urtigas.");
    b->dados[JO].capitulos[30].versos[8] = _("São filhos de insensatos, filhos de gente sem nome; da terra foram enxotados.");
    b->dados[JO].capitulos[30].versos[9] = _("Mas agora vim a ser a sua canção, e lhes sirvo de provérbio.");
    b->dados[JO].capitulos[30].versos[10] = _("Eles me abominam, afastam-se de mim, e no meu rosto não se privam de cuspir.");
    b->dados[JO].capitulos[30].versos[11] = _("Porquanto Deus desatou a minha corda e me humilhou, eles sacudiram de si o freio perante o meu rosto.");
    b->dados[JO].capitulos[30].versos[12] = _("À direita levanta-se gente vil; empurram os meus pés, e contra mim erigem os seus caminhos de destruição.");
    b->dados[JO].capitulos[30].versos[13] = _("Estragam a minha vereda, promovem a minha calamidade; não há quem os detenha.");
    b->dados[JO].capitulos[30].versos[14] = _("Vêm como por uma grande brecha, por entre as ruínas se precipitam.");
    b->dados[JO].capitulos[30].versos[15] = _("Sobrevieram-me pavores; é perseguida a minha honra como pelo vento; e como nuvem passou a minha felicidade.");
    b->dados[JO].capitulos[30].versos[16] = _("E agora dentro de mim se derrama a minha alma; os dias da aflição se apoderaram de mim.");
    b->dados[JO].capitulos[30].versos[17] = _("De noite me são traspassados os ossos, e o mal que me corrói não descansa.");
    b->dados[JO].capitulos[30].versos[18] = _("Pela violência do mal está desfigurada a minha veste; como a gola da minha túnica, me aperta.");
    b->dados[JO].capitulos[30].versos[19] = _("Ele me lançou na lama, e fiquei semelhante ao pó e à cinza.");
    b->dados[JO].capitulos[30].versos[20] = _("Clamo a ti, e não me respondes; ponho-me em pé, e não atentas para mim.");
    b->dados[JO].capitulos[30].versos[21] = _("Tornas-te cruel para comigo; com a força da tua mão me persegues.");
    b->dados[JO].capitulos[30].versos[22] = _("Levantas-me sobre o vento, fazes-me cavalgar sobre ele, e dissolves-me na tempestade.");
    b->dados[JO].capitulos[30].versos[23] = _("Pois eu sei que me levarás à morte, e à casa do ajuntamento destinada a todos os viventes.");
    b->dados[JO].capitulos[30].versos[24] = _("Contudo não estende a mão quem está a cair? ou não clama por socorro na sua calamidade?");
    b->dados[JO].capitulos[30].versos[25] = _("Não chorava eu sobre aquele que estava aflito? ou não se angustiava a minha alma pelo necessitado?");
    b->dados[JO].capitulos[30].versos[26] = _("Todavia aguardando eu o bem, eis que me veio o mal, e esperando eu a luz, veio a escuridão.");
    b->dados[JO].capitulos[30].versos[27] = _("As minhas entranhas fervem e não descansam; os dias da aflição me surpreenderam.");
    b->dados[JO].capitulos[30].versos[28] = _("Denegrido ando, mas não do sol; levanto-me na congregação, e clamo por socorro.");
    b->dados[JO].capitulos[30].versos[29] = _("Tornei-me irmão dos chacais, e companheiro dos avestruzes.");
    b->dados[JO].capitulos[30].versos[30] = _("A minha pele enegrece e se me cai, e os meus ossos estão queimados do calor.");
    b->dados[JO].capitulos[30].versos[31] = _("Pelo que se tornou em pranto a minha harpa, e a minha flauta em voz dos que choram.");

    b->dados[JO].capitulos[31].versos[1] = _("Fiz pacto com os meus olhos; como, pois, os fixaria numa virgem?");
    b->dados[JO].capitulos[31].versos[2] = _("Pois que porção teria eu de Deus lá de cima, e que herança do Todo-Poderoso lá do alto?");
    b->dados[JO].capitulos[31].versos[3] = _("Não é a destruição para o perverso, e o desastre para os obradores da iniqüidade?");
    b->dados[JO].capitulos[31].versos[4] = _("Não vê ele os meus caminhos, e não conta todos os meus passos?");
    b->dados[JO].capitulos[31].versos[5] = _("Se eu tenho andado com falsidade, e se o meu pé se tem apressado após o engano");
    b->dados[JO].capitulos[31].versos[6] = _("{pese-me Deus em balanças fiéis, e conheça a minha integridade};");
    b->dados[JO].capitulos[31].versos[7] = _("se os meus passos se têm desviado do caminho, e se o meu coração tem seguido os meus olhos, e se qualquer mancha se tem pegado às minhas mãos;");
    b->dados[JO].capitulos[31].versos[8] = _("então semeie eu e outro coma, e seja arrancado o produto do meu campo.");
    b->dados[JO].capitulos[31].versos[9] = _("Se o meu coração se deixou seduzir por causa duma mulher, ou se eu tenho armado traição à porta do meu próximo,");
    b->dados[JO].capitulos[31].versos[10] = _("então moa minha mulher para outro, e outros se encurvem sobre ela.");
    b->dados[JO].capitulos[31].versos[11] = _("Pois isso seria um crime infame; sim, isso seria uma iniqüidade para ser punida pelos juízes;");
    b->dados[JO].capitulos[31].versos[12] = _("porque seria fogo que consome até Abadom, e desarraigaria toda a minha renda.");
    b->dados[JO].capitulos[31].versos[13] = _("Se desprezei o direito do meu servo ou da minha serva, quando eles pleitearam comigo,");
    b->dados[JO].capitulos[31].versos[14] = _("então que faria eu quando Deus se levantasse? E quando ele me viesse inquirir, que lhe responderia?");
    b->dados[JO].capitulos[31].versos[15] = _("Aquele que me formou no ventre não o fez também a meu servo? E não foi um que nos plasmou na madre?");
    b->dados[JO].capitulos[31].versos[16] = _("Se tenho negado aos pobres o que desejavam, ou feito desfalecer os olhos da viúva,");
    b->dados[JO].capitulos[31].versos[17] = _("ou se tenho comido sozinho o meu bocado, e não tem comido dele o órfão também");
    b->dados[JO].capitulos[31].versos[18] = _("{pois desde a minha mocidade o órfão cresceu comigo como com seu pai, e a viúva, tenho-a guiado desde o ventre de minha mãe};");
    b->dados[JO].capitulos[31].versos[19] = _("se tenho visto alguém perecer por falta de roupa, ou o necessitado não ter com que se cobrir;");
    b->dados[JO].capitulos[31].versos[20] = _("se os seus lombos não me abençoaram, se ele não se aquentava com os velos dos meus cordeiros;");
    b->dados[JO].capitulos[31].versos[21] = _("se levantei a minha mão contra o órfão, porque na porta via a minha ajuda;");
    b->dados[JO].capitulos[31].versos[22] = _("então caia do ombro a minha espádua, e separe-se o meu braço da sua juntura.");
    b->dados[JO].capitulos[31].versos[23] = _("Pois a calamidade vinda de Deus seria para mim um horror, e eu não poderia suportar a sua majestade.");
    b->dados[JO].capitulos[31].versos[24] = _("Se do ouro fiz a minha esperança, ou disse ao ouro fino: Tu és a minha confiança;");
    b->dados[JO].capitulos[31].versos[25] = _("se me regozijei por ser grande a minha riqueza, e por ter a minha mão alcança o muito;");
    b->dados[JO].capitulos[31].versos[26] = _("se olhei para o sol, quando resplandecia, ou para a lua, quando ela caminhava em esplendor,");
    b->dados[JO].capitulos[31].versos[27] = _("e o meu coração se deixou enganar em oculto, e a minha boca beijou a minha mão;");
    b->dados[JO].capitulos[31].versos[28] = _("isso também seria uma iniqüidade para ser punida pelos juízes; pois assim teria negado a Deus que está lá em cima.");
    b->dados[JO].capitulos[31].versos[29] = _("Se me regozijei com a ruína do que me tem ódio, e se exultei quando o mal lhe sobreveio");
    b->dados[JO].capitulos[31].versos[30] = _("{mas eu não deixei pecar a minha boca, pedindo com imprecação a sua morte};");
    b->dados[JO].capitulos[31].versos[31] = _("se as pessoas da minha tenda não disseram: Quem há que não se tenha saciado com carne provida por ele?");
    b->dados[JO].capitulos[31].versos[32] = _("O estrangeiro não passava a noite na rua; mas eu abria as minhas portas ao viandante;");
    b->dados[JO].capitulos[31].versos[33] = _("se, como Adão, encobri as minhas transgressões, ocultando a minha iniqüidade no meu seio,");
    b->dados[JO].capitulos[31].versos[34] = _("porque tinha medo da grande multidão, e o desprezo das famílias me aterrorizava, de modo que me calei, e não saí da porta...");
    b->dados[JO].capitulos[31].versos[35] = _("Ah! quem me dera um que me ouvisse! Eis a minha defesa, que me responda o Todo-Poderoso! Oxalá tivesse eu a acusação escrita pelo meu adversário!");
    b->dados[JO].capitulos[31].versos[36] = _("Por certo eu a levaria sobre o ombro, sobre mim a ataria como coroa.");
    b->dados[JO].capitulos[31].versos[37] = _("Eu lhe daria conta dos meus passos; como príncipe me chegaria a ele");
    b->dados[JO].capitulos[31].versos[38] = _("Se a minha terra clamar contra mim, e se os seus sulcos juntamente chorarem;");
    b->dados[JO].capitulos[31].versos[39] = _("se comi os seus frutos sem dinheiro, ou se fiz que morressem os seus donos;");
    b->dados[JO].capitulos[31].versos[40] = _("por trigo me produza cardos, e por cevada joio. Acabaram-se as palavras de Jó.");

    b->dados[JO].capitulos[32].versos[1] = _("E aqueles três homens cessaram de responder a Jó; porque era justo aos seus próprios olhos.");
    b->dados[JO].capitulos[32].versos[2] = _("Então se acendeu a ira de Eliú, filho de Baraquel, o buzita, da família de Rão; acendeu-se a sua ira contra Jó, porque este se justificava a si mesmo, e não a Deus.");
    b->dados[JO].capitulos[32].versos[3] = _("Também contra os seus três amigos se acendeu a sua ira, porque não tinham achado o que responder, e contudo tinham condenado a Jó.");
    b->dados[JO].capitulos[32].versos[4] = _("Ora, Eliú havia esperado para falar a Jó, porque eles eram mais idosos do que ele.");
    b->dados[JO].capitulos[32].versos[5] = _("Quando, pois, Eliú viu que não havia resposta na boca daqueles três homens, acendeu-se-lhe a ira.");
    b->dados[JO].capitulos[32].versos[6] = _("Então respondeu Eliú, filho de Baraquel, o buzita, dizendo: Eu sou de pouca idade, e vós sois, idosos; arreceei-me e temi de vos declarar a minha opinião.");
    b->dados[JO].capitulos[32].versos[7] = _("Dizia eu: Falem os dias, e a multidão dos anos ensine a sabedoria.");
    b->dados[JO].capitulos[32].versos[8] = _("Há, porém, um espírito no homem, e o sopro do Todo-Poderoso o faz entendido.");
    b->dados[JO].capitulos[32].versos[9] = _("Não são os velhos que são os sábios, nem os anciãos que entendem o que é reto.");
    b->dados[JO].capitulos[32].versos[10] = _("Pelo que digo: Ouvi-me, e também eu declararei a minha opinião.");
    b->dados[JO].capitulos[32].versos[11] = _("Eis que aguardei as vossas palavras, escutei as vossas considerações, enquanto buscáveis o que dizer.");
    b->dados[JO].capitulos[32].versos[12] = _("Eu, pois, vos prestava toda a minha atenção, e eis que não houve entre vós quem convencesse a Jó, nem quem respondesse às suas palavras;");
    b->dados[JO].capitulos[32].versos[13] = _("pelo que não digais: Achamos a sabedoria; Deus é que pode derrubá-lo, e não o homem.");
    b->dados[JO].capitulos[32].versos[14] = _("Ora ele não dirigiu contra mim palavra alguma, nem lhe responderei com as vossas palavras.");
    b->dados[JO].capitulos[32].versos[15] = _("Estão pasmados, não respondem mais; faltam-lhes as palavras.");
    b->dados[JO].capitulos[32].versos[16] = _("Hei de eu esperar, porque eles não falam, porque já pararam, e não respondem mais?");
    b->dados[JO].capitulos[32].versos[17] = _("Eu também darei a minha resposta; eu também declararei a minha opinião.");
    b->dados[JO].capitulos[32].versos[18] = _("Pois estou cheio de palavras; o espírito dentro de mim me constrange.");
    b->dados[JO].capitulos[32].versos[19] = _("Eis que o meu peito é como o mosto, sem respiradouro, como odres novos que estão para arrebentar.");
    b->dados[JO].capitulos[32].versos[20] = _("Falarei, para que ache alívio; abrirei os meus lábios e responderei:");
    b->dados[JO].capitulos[32].versos[21] = _("Que não faça eu acepção de pessoas, nem use de lisonjas para com o homem.");
    b->dados[JO].capitulos[32].versos[22] = _("Porque não sei usar de lisonjas; do contrário, em breve me levaria o meu Criador.");

    b->dados[JO].capitulos[33].versos[1] = _("Ouve, pois, as minhas palavras, ó Jó, e dá ouvidos a todas as minhas declarações.");
    b->dados[JO].capitulos[33].versos[2] = _("Eis que já abri a minha boca; já falou a minha língua debaixo do meu paladar.");
    b->dados[JO].capitulos[33].versos[3] = _("As minhas palavras declaram a integridade do meu coração, e os meus lábios falam com sinceridade o que sabem.");
    b->dados[JO].capitulos[33].versos[4] = _("O Espírito de Deus me fez, e o sopro do Todo-Poderoso me dá vida.");
    b->dados[JO].capitulos[33].versos[5] = _("Se podes, responde-me; põe as tuas palavras em ordem diante de mim; apresenta-te.");
    b->dados[JO].capitulos[33].versos[6] = _("Eis que diante de Deus sou o que tu és; eu também fui formado do barro.");
    b->dados[JO].capitulos[33].versos[7] = _("Eis que não te perturbará nenhum medo de mim, nem será pesada sobre ti a minha mão.");
    b->dados[JO].capitulos[33].versos[8] = _("Na verdade tu falaste aos meus ouvidos, e eu ouvi a voz das tuas palavras. Dizias:");
    b->dados[JO].capitulos[33].versos[9] = _("Limpo estou, sem transgressão; puro sou, e não há em mim iniqüidade.");
    b->dados[JO].capitulos[33].versos[10] = _("Eis que Deus procura motivos de inimizade contra mim, e me considera como o seu inimigo.");
    b->dados[JO].capitulos[33].versos[11] = _("Põe no tronco os meus pés, e observa todas as minhas veredas.");
    b->dados[JO].capitulos[33].versos[12] = _("Eis que nisso não tens razão; eu te responderei; porque Deus e maior do que o homem.");
    b->dados[JO].capitulos[33].versos[13] = _("Por que razão contendes com ele por não dar conta dos seus atos?");
    b->dados[JO].capitulos[33].versos[14] = _("Pois Deus fala de um modo, e ainda de outro se o homem não lhe atende.");
    b->dados[JO].capitulos[33].versos[15] = _("Em sonho ou em visão de noite, quando cai sono profundo sobre os homens, quando adormecem na cama;");
    b->dados[JO].capitulos[33].versos[16] = _("então abre os ouvidos dos homens, e os atemoriza com avisos,");
    b->dados[JO].capitulos[33].versos[17] = _("para apartar o homem do seu desígnio, e esconder do homem a soberba;");
    b->dados[JO].capitulos[33].versos[18] = _("para reter a sua alma da cova, e a sua vida de passar pela espada.");
    b->dados[JO].capitulos[33].versos[19] = _("Também é castigado na sua cama com dores, e com incessante contenda nos seus ossos;");
    b->dados[JO].capitulos[33].versos[20] = _("de modo que a sua vida abomina o pão, e a sua alma a comida apetecível.");
    b->dados[JO].capitulos[33].versos[21] = _("Consome-se a sua carne, de maneira que desaparece, e os seus ossos, que não se viam, agora aparecem.");
    b->dados[JO].capitulos[33].versos[22] = _("A sua alma se vai chegando à cova, e a sua vida aos que trazem a morte.");
    b->dados[JO].capitulos[33].versos[23] = _("Se com ele, pois, houver um anjo, um intérprete, um entre mil, para declarar ao homem o que lhe é justo,");
    b->dados[JO].capitulos[33].versos[24] = _("então terá compaixão dele, e lhe dirá: Livra-o, para que não desça à cova; já achei resgate.");
    b->dados[JO].capitulos[33].versos[25] = _("Sua carne se reverdecerá mais do que na sua infância; e ele tornará aos dias da sua juventude.");
    b->dados[JO].capitulos[33].versos[26] = _("Deveras orará a Deus, que lhe será propício, e o fará ver a sua face com júbilo, e restituirá ao homem a sua justiça.");
    b->dados[JO].capitulos[33].versos[27] = _("Cantará diante dos homens, e dirá: Pequei, e perverti o direito, o que de nada me aproveitou.");
    b->dados[JO].capitulos[33].versos[28] = _("Mas Deus livrou a minha alma de ir para a cova, e a minha vida verá a luz.");
    b->dados[JO].capitulos[33].versos[29] = _("Eis que tudo isto Deus faz duas e três vezes para com o homem,");
    b->dados[JO].capitulos[33].versos[30] = _("para reconduzir a sua alma da cova, a fim de que seja iluminado com a luz dos viventes.");
    b->dados[JO].capitulos[33].versos[31] = _("Escuta, pois, ó Jó, ouve-me; cala-te, e eu falarei.");
    b->dados[JO].capitulos[33].versos[32] = _("Se tens alguma coisa que dizer, responde-me; fala, porque desejo justificar-te.");
    b->dados[JO].capitulos[33].versos[33] = _("Se não, escuta-me tu; cala-te, e ensinar-te-ei a sabedoria.");

    b->dados[JO].capitulos[34].versos[1] = _("Prosseguiu Eliú, dizendo:");
    b->dados[JO].capitulos[34].versos[2] = _("Ouvi, vós, sábios, as minhas palavras; e vós, entendidos, inclinai os ouvidos para mim.");
    b->dados[JO].capitulos[34].versos[3] = _("Pois o ouvido prova as palavras, como o paladar experimenta a comida.");
    b->dados[JO].capitulos[34].versos[4] = _("O que é direito escolhamos para nós; e conheçamos entre nós o que é bom.");
    b->dados[JO].capitulos[34].versos[5] = _("Pois Jó disse: Sou justo, e Deus tirou-me o direito.");
    b->dados[JO].capitulos[34].versos[6] = _("Apesar do meu direito, sou considerado mentiroso; a minha ferida é incurável, embora eu esteja sem transgressão.");
    b->dados[JO].capitulos[34].versos[7] = _("Que homem há como Jó, que bebe o escárnio como água,");
    b->dados[JO].capitulos[34].versos[8] = _("que anda na companhia dos malfeitores, e caminha com homens ímpios?");
    b->dados[JO].capitulos[34].versos[9] = _("Porque disse: De nada aproveita ao homem o comprazer-se em Deus.");
    b->dados[JO].capitulos[34].versos[10] = _("Pelo que ouvi-me, vós homens de entendimento: longe de Deus o praticar a maldade, e do Todo-Poderoso o cometer a iniqüidade!");
    b->dados[JO].capitulos[34].versos[11] = _("Pois, segundo a obra do homem, ele lhe retribui, e faz a cada um segundo o seu caminho.");
    b->dados[JO].capitulos[34].versos[12] = _("Na verdade, Deus não procederá impiamente, nem o Todo-Poderoso perverterá o juízo.");
    b->dados[JO].capitulos[34].versos[13] = _("Quem lhe entregou o governo da terra? E quem lhe deu autoridade sobre o mundo todo?");
    b->dados[JO].capitulos[34].versos[14] = _("Se ele retirasse para si o seu espírito, e recolhesse para si o seu fôlego,");
    b->dados[JO].capitulos[34].versos[15] = _("toda a carne juntamente expiraria, e o homem voltaria para o pó.");
    b->dados[JO].capitulos[34].versos[16] = _("Se, pois, há em ti entendimento, ouve isto, inclina os ouvidos às palavras que profiro.");
    b->dados[JO].capitulos[34].versos[17] = _("Acaso quem odeia o direito governará? Quererás tu condenar aquele que é justo e poderoso?");
    b->dados[JO].capitulos[34].versos[18] = _("aquele que diz a um rei: Ó vil? e aos príncipes: Ó ímpios?");
    b->dados[JO].capitulos[34].versos[19] = _("que não faz acepção das pessoas de príncipes, nem estima o rico mais do que o pobre; porque todos são obra de suas mãos?");
    b->dados[JO].capitulos[34].versos[20] = _("Eles num momento morrem; e à meia-noite os povos são perturbados, e passam, e os poderosos são levados não por mão humana.");
    b->dados[JO].capitulos[34].versos[21] = _("Porque os seus olhos estão sobre os caminhos de cada um, e ele vê todos os seus passos.");
    b->dados[JO].capitulos[34].versos[22] = _("Não há escuridão nem densas trevas, onde se escondam os obradores da iniqüidade.");
    b->dados[JO].capitulos[34].versos[23] = _("Porque Deus não precisa observar por muito tempo o homem para que este compareça perante ele em juízo.");
    b->dados[JO].capitulos[34].versos[24] = _("Ele quebranta os fortes, sem inquirição, e põe outros em lugar deles.");
    b->dados[JO].capitulos[34].versos[25] = _("Pois conhecendo ele as suas obras, de noite os transtorna, e ficam esmagados.");
    b->dados[JO].capitulos[34].versos[26] = _("Ele os fere como ímpios, à vista dos circunstantes;");
    b->dados[JO].capitulos[34].versos[27] = _("porquanto se desviaram dele, e não quiseram compreender nenhum de seus caminhos,");
    b->dados[JO].capitulos[34].versos[28] = _("de sorte que o clamor do pobre subisse até ele, e que ouvisse o clamor dos aflitos.");
    b->dados[JO].capitulos[34].versos[29] = _("Se ele dá tranqüilidade, quem então o condenará? Se ele encobrir o rosto, quem então o poderá contemplar, quer seja uma nação, quer seja um homem só?");
    b->dados[JO].capitulos[34].versos[30] = _("para que o ímpio não reine, e não haja quem iluda o povo.");
    b->dados[JO].capitulos[34].versos[31] = _("Pois, quem jamais disse a Deus: Sofri, ainda que não pequei;");
    b->dados[JO].capitulos[34].versos[32] = _("o que não vejo, ensina-me tu; se fiz alguma maldade, nunca mais a hei de fazer?");
    b->dados[JO].capitulos[34].versos[33] = _("Será a sua recompensa como queres, para que a recuses? Pois tu tens que fazer a escolha, e não eu; portanto fala o que sabes.");
    b->dados[JO].capitulos[34].versos[34] = _("Os homens de entendimento dir-me-ão, e o varão sábio, que me ouvir:");
    b->dados[JO].capitulos[34].versos[35] = _("Jó fala sem conhecimento, e às suas palavras falta sabedoria.");
    b->dados[JO].capitulos[34].versos[36] = _("Oxalá que Jó fosse provado até o fim; porque responde como os iníquos.");
    b->dados[JO].capitulos[34].versos[37] = _("Porque ao seu pecado acrescenta a rebelião; entre nós bate as palmas, e multiplica contra Deus as suas palavras.");

    b->dados[JO].capitulos[35].versos[1] = _("Disse mais Eliú:");
    b->dados[JO].capitulos[35].versos[2] = _("Tens por direito dizeres: Maior é a minha justiça do que a de Deus?");
    b->dados[JO].capitulos[35].versos[3] = _("Porque dizes: Que me aproveita? Que proveito tenho mais do que se eu tivera pecado?");
    b->dados[JO].capitulos[35].versos[4] = _("Eu te darei respostas, a ti e aos teus amigos contigo.");
    b->dados[JO].capitulos[35].versos[5] = _("Atenta para os céus, e vê; e contempla o firmamento que é mais alto do que tu.");
    b->dados[JO].capitulos[35].versos[6] = _("Se pecares, que efetuarás contra ele? Se as tuas transgressões se multiplicarem, que lhe farás com isso?");
    b->dados[JO].capitulos[35].versos[7] = _("Se fores justo, que lhe darás, ou que receberá ele da tua mão?");
    b->dados[JO].capitulos[35].versos[8] = _("A tua impiedade poderia fazer mal a outro tal como tu; e a tua justiça poderia aproveitar a um filho do homem.");
    b->dados[JO].capitulos[35].versos[9] = _("Por causa da multidão das opressões os homens clamam; clamam por socorro por causa do braço dos poderosos.");
    b->dados[JO].capitulos[35].versos[10] = _("Mas ninguém diz: Onde está Deus meu Criador, que inspira canções durante a noite;");
    b->dados[JO].capitulos[35].versos[11] = _("que nos ensina mais do que aos animais da terra, e nos faz mais sábios do que as aves do céu?");
    b->dados[JO].capitulos[35].versos[12] = _("Ali clamam, porém ele não responde, por causa da arrogância os maus.");
    b->dados[JO].capitulos[35].versos[13] = _("Certo é que Deus não ouve o grito da vaidade, nem para ela atentará o Todo-Poderoso.");
    b->dados[JO].capitulos[35].versos[14] = _("Quanto menos quando tu dizes que não o vês. A causa está perante ele; por isso espera nele.");
    b->dados[JO].capitulos[35].versos[15] = _("Mas agora, porque a sua ira ainda não se exerce, nem grandemente considera ele a arrogância,");
    b->dados[JO].capitulos[35].versos[16] = _("por isso abre Jó em vão a sua boca, e sem conhecimento multiplica palavras.");

    b->dados[JO].capitulos[36].versos[1] = _("Prosseguiu ainda Eliú e disse:");
    b->dados[JO].capitulos[36].versos[2] = _("Espera-me um pouco, e mostrar-te-ei que ainda há razões a favor de Deus.");
    b->dados[JO].capitulos[36].versos[3] = _("De longe trarei o meu conhecimento, e ao meu criador atribuirei a justiça.");
    b->dados[JO].capitulos[36].versos[4] = _("Pois, na verdade, as minhas palavras não serão falsas; contigo está um que tem perfeito conhecimento.");
    b->dados[JO].capitulos[36].versos[5] = _("Eis que Deus é mui poderoso, contudo a ninguém despreza; grande é no poder de entendimento.");
    b->dados[JO].capitulos[36].versos[6] = _("Ele não preserva a vida do ímpio, mas faz justiça aos aflitos.");
    b->dados[JO].capitulos[36].versos[7] = _("Do justo não aparta os seus olhos; antes com os reis no trono os faz sentar para sempre, e assim são exaltados.");
    b->dados[JO].capitulos[36].versos[8] = _("E se estão presos em grilhões, e amarrados com cordas de aflição,");
    b->dados[JO].capitulos[36].versos[9] = _("então lhes faz saber a obra deles, e as suas transgressões, porquanto se têm portado com soberba.");
    b->dados[JO].capitulos[36].versos[10] = _("E abre-lhes o ouvido para a instrução, e ordena que se convertam da iniqüidade.");
    b->dados[JO].capitulos[36].versos[11] = _("Se o ouvirem, e o servirem, acabarão seus dias em prosperidade, e os seus anos em delícias.");
    b->dados[JO].capitulos[36].versos[12] = _("Mas se não o ouvirem, à espada serão passados, e expirarão sem conhecimento.");
    b->dados[JO].capitulos[36].versos[13] = _("Assim os ímpios de coração amontoam, a sua ira; e quando Deus os põe em grilhões, não clamam por socorro.");
    b->dados[JO].capitulos[36].versos[14] = _("Eles morrem na mocidade, e a sua vida perece entre as prostitutas.");
    b->dados[JO].capitulos[36].versos[15] = _("Ao aflito livra por meio da sua aflição, e por meio da opressão lhe abre os ouvidos.");
    b->dados[JO].capitulos[36].versos[16] = _("Assim também quer induzir-te da angústia para um lugar espaçoso, em que não há aperto; e as iguarias da tua mesa serão cheias de gordura.");
    b->dados[JO].capitulos[36].versos[17] = _("Mas tu estás cheio do juízo do ímpio; o juízo e a justiça tomam conta de ti.");
    b->dados[JO].capitulos[36].versos[18] = _("Cuida, pois, para que a ira não te induza a escarnecer, nem te desvie a grandeza do resgate.");
    b->dados[JO].capitulos[36].versos[19] = _("Prevalecerá o teu clamor, ou todas as forças da tua fortaleza, para que não estejas em aperto?");
    b->dados[JO].capitulos[36].versos[20] = _("Não suspires pela noite, em que os povos sejam tomados do seu lugar.");
    b->dados[JO].capitulos[36].versos[21] = _("Guarda-te, e não declines para a iniqüidade; porquanto isso escolheste antes que a aflição.");
    b->dados[JO].capitulos[36].versos[22] = _("Eis que Deus é excelso em seu poder; quem é ensinador como ele?");
    b->dados[JO].capitulos[36].versos[23] = _("Quem lhe prescreveu o seu caminho? Ou quem poderá dizer: Tu praticaste a injustiça?");
    b->dados[JO].capitulos[36].versos[24] = _("Lembra-te de engrandecer a sua obra, de que têm cantado os homens.");
    b->dados[JO].capitulos[36].versos[25] = _("Todos os homens a vêem; de longe a contempla o homem.");
    b->dados[JO].capitulos[36].versos[26] = _("Eis que Deus é grande, e nós não o conhecemos, e o número dos seus anos não se pode esquadrinhar.");
    b->dados[JO].capitulos[36].versos[27] = _("Pois atrai a si as gotas de água, e do seu vapor as destila em chuva,");
    b->dados[JO].capitulos[36].versos[28] = _("que as nuvens derramam e gotejam abundantemente sobre o homem.");
    b->dados[JO].capitulos[36].versos[29] = _("Poderá alguém entender as dilatações das nuvens, e os trovões do seu pavilhão?");
    b->dados[JO].capitulos[36].versos[30] = _("Eis que ao redor de si estende a sua luz, e cobre o fundo do mar.");
    b->dados[JO].capitulos[36].versos[31] = _("Pois por estas coisas julga os povos e lhes dá mantimento em abundância.");
    b->dados[JO].capitulos[36].versos[32] = _("Cobre as mãos com o relâmpago, e dá-lhe ordem para que fira o alvo.");
    b->dados[JO].capitulos[36].versos[33] = _("O fragor da tempestade dá notícia dele; até o gado pressente a sua aproximação.");

    b->dados[JO].capitulos[37].versos[1] = _("Sobre isso também treme o meu coração, e salta do seu lugar.");
    b->dados[JO].capitulos[37].versos[2] = _("Dai atentamente ouvidos ao estrondo da voz de Deus e ao sonido que sai da sua boca.");
    b->dados[JO].capitulos[37].versos[3] = _("Ele o envia por debaixo de todo o céu, e o seu relâmpago até os confins da terra.");
    b->dados[JO].capitulos[37].versos[4] = _("Depois do relâmpago ruge uma grande voz; ele troveja com a sua voz majestosa; e não retarda os raios, quando é ouvida a sua voz.");
    b->dados[JO].capitulos[37].versos[5] = _("Com a sua voz troveja Deus maravilhosamente; faz grandes coisas, que nós não compreendemos.");
    b->dados[JO].capitulos[37].versos[6] = _("Pois à neve diz: Cai sobre a terra; como também às chuvas e aos aguaceiros: Sede copiosos.");
    b->dados[JO].capitulos[37].versos[7] = _("Ele sela as mãos de todo homem, para que todos saibam que ele os fez.");
    b->dados[JO].capitulos[37].versos[8] = _("E as feras entram nos esconderijos e ficam nos seus covis.");
    b->dados[JO].capitulos[37].versos[9] = _("Da recâmara do sul sai o tufão, e do norte o frio.");
    b->dados[JO].capitulos[37].versos[10] = _("Ao sopro de Deus forma-se o gelo, e as largas águas são congeladas.");
    b->dados[JO].capitulos[37].versos[11] = _("Também de umidade carrega as grossas nuvens; as nuvens espalham relâmpagos.");
    b->dados[JO].capitulos[37].versos[12] = _("Fazem evoluções sob a sua direção, para efetuar tudo quanto lhes ordena sobre a superfície do mundo habitável:");
    b->dados[JO].capitulos[37].versos[13] = _("seja para disciplina, ou para a sua terra, ou para beneficência, que as faça vir.");
    b->dados[JO].capitulos[37].versos[14] = _("A isto, Jó, inclina os teus ouvidos; pára e considera as obras maravilhosas de Deus.");
    b->dados[JO].capitulos[37].versos[15] = _("Sabes tu como Deus lhes dá as suas ordens, e faz resplandecer o relâmpago da sua nuvem?");
    b->dados[JO].capitulos[37].versos[16] = _("Compreendes o equilíbrio das nuvens, e as maravilhas daquele que é perfeito nos conhecimentos;");
    b->dados[JO].capitulos[37].versos[17] = _("tu cujas vestes são quentes, quando há calma sobre a terra por causa do vento sul?");
    b->dados[JO].capitulos[37].versos[18] = _("Acaso podes, como ele, estender o firmamento, que é sólido como um espelho fundido?");
    b->dados[JO].capitulos[37].versos[19] = _("Ensina-nos o que lhe diremos; pois nós nada poderemos pôr em boa ordem, por causa das trevas.");
    b->dados[JO].capitulos[37].versos[20] = _("Contar-lhe-ia alguém que eu quero falar. Ou desejaria um homem ser devorado?");
    b->dados[JO].capitulos[37].versos[21] = _("E agora o homem não pode olhar para o sol, que resplandece no céu quando o vento, tendo passado, o deixa limpo.");
    b->dados[JO].capitulos[37].versos[22] = _("Do norte vem o áureo esplendor; em Deus há tremenda majestade.");
    b->dados[JO].capitulos[37].versos[23] = _("Quanto ao Todo-Poderoso, não o podemos compreender; grande é em poder e justiça e pleno de retidão; a ninguém, pois, oprimirá.");
    b->dados[JO].capitulos[37].versos[24] = _("Por isso o temem os homens; ele não respeita os que se julgam sábios.");

    b->dados[JO].capitulos[38].versos[1] = _("Depois disso o Senhor respondeu a Jó dum redemoinho, dizendo:");
    b->dados[JO].capitulos[38].versos[2] = _("Quem é este que escurece o conselho com palavras sem conhecimento?");
    b->dados[JO].capitulos[38].versos[3] = _("Agora cinge os teus lombos, como homem; porque te perguntarei, e tu me responderás.");
    b->dados[JO].capitulos[38].versos[4] = _("Onde estavas tu, quando eu lançava os fundamentos da terra? Faze-mo saber, se tens entendimento.");
    b->dados[JO].capitulos[38].versos[5] = _("Quem lhe fixou as medidas, se é que o sabes? ou quem a mediu com o cordel?");
    b->dados[JO].capitulos[38].versos[6] = _("Sobre que foram firmadas as suas bases, ou quem lhe assentou a pedra de esquina,");
    b->dados[JO].capitulos[38].versos[7] = _("quando juntas cantavam as estrelas da manhã, e todos os filhos de Deus bradavam de júbilo?");
    b->dados[JO].capitulos[38].versos[8] = _("Ou quem encerrou com portas o mar, quando este rompeu e saiu da madre;");
    b->dados[JO].capitulos[38].versos[9] = _("quando eu lhe pus nuvens por vestidura, e escuridão por faixas,");
    b->dados[JO].capitulos[38].versos[10] = _("e lhe tracei limites, pondo-lhe portas e ferrolhos,");
    b->dados[JO].capitulos[38].versos[11] = _("e lhe disse: Até aqui virás, porém não mais adiante; e aqui se quebrarão as tuas ondas orgulhosas?");
    b->dados[JO].capitulos[38].versos[12] = _("Desde que começaram os teus dias, deste tu ordem à madrugada, ou mostraste à alva o seu lugar,");
    b->dados[JO].capitulos[38].versos[13] = _("para que agarrasse nas extremidades da terra, e os ímpios fossem sacudidos dela?");
    b->dados[JO].capitulos[38].versos[14] = _("A terra se transforma como o barro sob o selo; e todas as coisas se assinalam como as cores dum vestido.");
    b->dados[JO].capitulos[38].versos[15] = _("E dos ímpios é retirada a sua luz, e o braço altivo se quebranta.");
    b->dados[JO].capitulos[38].versos[16] = _("Acaso tu entraste até os mananciais do mar, ou passeaste pelos recessos do abismo?");
    b->dados[JO].capitulos[38].versos[17] = _("Ou foram-te descobertas as portas da morte, ou viste as portas da sombra da morte?");
    b->dados[JO].capitulos[38].versos[18] = _("Compreendeste a largura da terra? Faze-mo saber, se sabes tudo isso.");
    b->dados[JO].capitulos[38].versos[19] = _("Onde está o caminho para a morada da luz? E, quanto às trevas, onde está o seu lugar,");
    b->dados[JO].capitulos[38].versos[20] = _("para que às tragas aos seus limites, e para que saibas as veredas para a sua casa?");
    b->dados[JO].capitulos[38].versos[21] = _("De certo tu o sabes, porque já então eras nascido, e porque é grande o número dos teus dias!");
    b->dados[JO].capitulos[38].versos[22] = _("Acaso entraste nos tesouros da neve, e viste os tesouros da saraiva,");
    b->dados[JO].capitulos[38].versos[23] = _("que eu tenho reservado para o tempo da angústia, para o dia da peleja e da guerra?");
    b->dados[JO].capitulos[38].versos[24] = _("Onde está o caminho para o lugar em que se reparte a luz, e se espalha o vento oriental sobre a terra?");
    b->dados[JO].capitulos[38].versos[25] = _("Quem abriu canais para o aguaceiro, e um caminho para o relâmpago do trovão;");
    b->dados[JO].capitulos[38].versos[26] = _("para fazer cair chuva numa terra, onde não há ninguém, e no deserto, em que não há gente;");
    b->dados[JO].capitulos[38].versos[27] = _("para fartar a terra deserta e assolada, e para fazer crescer a tenra relva?");
    b->dados[JO].capitulos[38].versos[28] = _("A chuva porventura tem pai? Ou quem gerou as gotas do orvalho?");
    b->dados[JO].capitulos[38].versos[29] = _("Do ventre de quem saiu o gelo? E quem gerou a geada do céu?");
    b->dados[JO].capitulos[38].versos[30] = _("Como pedra as águas se endurecem, e a superfície do abismo se congela.");
    b->dados[JO].capitulos[38].versos[31] = _("Podes atar as cadeias das Plêiades, ou soltar os atilhos do Oriom?");
    b->dados[JO].capitulos[38].versos[32] = _("Ou fazer sair as constelações a seu tempo, e guiar a ursa com seus filhos?");
    b->dados[JO].capitulos[38].versos[33] = _("Sabes tu as ordenanças dos céus, ou podes estabelecer o seu domínio sobre a terra?");
    b->dados[JO].capitulos[38].versos[34] = _("Ou podes levantar a tua voz até as nuvens, para que a abundância das águas te cubra?");
    b->dados[JO].capitulos[38].versos[35] = _("Ou ordenarás aos raios de modo que saiam? Eles te dirão: Eis-nos aqui?");
    b->dados[JO].capitulos[38].versos[36] = _("Quem pôs sabedoria nas densas nuvens, ou quem deu entendimento ao meteoro?");
    b->dados[JO].capitulos[38].versos[37] = _("Quem numerará as nuvens pela sabedoria? Ou os odres do céu, quem os esvaziará,");
    b->dados[JO].capitulos[38].versos[38] = _("quando se funde o pó em massa, e se pegam os torrões uns aos outros?");
    b->dados[JO].capitulos[38].versos[39] = _("Podes caçar presa para a leoa, ou satisfazer a fome dos filhos dos leões,");
    b->dados[JO].capitulos[38].versos[40] = _("quando se agacham nos covis, e estão à espreita nas covas?");
    b->dados[JO].capitulos[38].versos[41] = _("Quem prepara ao corvo o seu alimento, quando os seus pintainhos clamam a Deus e andam vagueando, por não terem o que comer?");

    b->dados[JO].capitulos[39].versos[1] = _("Sabes tu o tempo do parto das cabras montesas, ou podes observar quando é que parem as corças?");
    b->dados[JO].capitulos[39].versos[2] = _("Podes contar os meses que cumprem, ou sabes o tempo do seu parto?");
    b->dados[JO].capitulos[39].versos[3] = _("Encurvam-se, dão à luz as suas crias, lançam de si a sua prole.");
    b->dados[JO].capitulos[39].versos[4] = _("Seus filhos enrijam, crescem no campo livre; saem, e não tornam para elas:");
    b->dados[JO].capitulos[39].versos[5] = _("Quem despediu livre o jumento montês, e quem soltou as prisões ao asno veloz,");
    b->dados[JO].capitulos[39].versos[6] = _("ao qual dei o ermo por casa, e a terra salgada por morada?");
    b->dados[JO].capitulos[39].versos[7] = _("Ele despreza o tumulto da cidade; não obedece os gritos do condutor.");
    b->dados[JO].capitulos[39].versos[8] = _("O circuito das montanhas é o seu pasto, e anda buscando tudo o que está verde.");
    b->dados[JO].capitulos[39].versos[9] = _("Quererá o boi selvagem servir-te? ou ficará junto à tua manjedoura?");
    b->dados[JO].capitulos[39].versos[10] = _("Podes amarrar o boi selvagem ao arado com uma corda, ou esterroará ele após ti os vales?");
    b->dados[JO].capitulos[39].versos[11] = _("Ou confiarás nele, por ser grande a sua força, ou deixarás a seu cargo o teu trabalho?");
    b->dados[JO].capitulos[39].versos[12] = _("Fiarás dele que te torne o que semeaste e o recolha à tua eira?");
    b->dados[JO].capitulos[39].versos[13] = _("Movem-se alegremente as asas da avestruz; mas é benigno o adorno da sua plumagem?");
    b->dados[JO].capitulos[39].versos[14] = _("Pois ela deixa os seus ovos na terra, e os aquenta no pó,");
    b->dados[JO].capitulos[39].versos[15] = _("e se esquece de que algum pé os pode pisar, ou de que a fera os pode calcar.");
    b->dados[JO].capitulos[39].versos[16] = _("Endurece-se para com seus filhos, como se não fossem seus; embora se perca o seu trabalho, ela está sem temor;");
    b->dados[JO].capitulos[39].versos[17] = _("porque Deus a privou de sabedoria, e não lhe repartiu entendimento.");
    b->dados[JO].capitulos[39].versos[18] = _("Quando ela se levanta para correr, zomba do cavalo, e do cavaleiro.");
    b->dados[JO].capitulos[39].versos[19] = _("Acaso deste força ao cavalo, ou revestiste de força o seu pescoço?");
    b->dados[JO].capitulos[39].versos[20] = _("Fizeste-o pular como o gafanhoto? Terrível é o fogoso respirar das suas ventas.");
    b->dados[JO].capitulos[39].versos[21] = _("Escarva no vale, e folga na sua força, e sai ao encontro dos armados.");
    b->dados[JO].capitulos[39].versos[22] = _("Ri-se do temor, e não se espanta; e não torna atrás por causa da espada.");
    b->dados[JO].capitulos[39].versos[23] = _("Sobre ele rangem a aljava, a lança cintilante e o dardo.");
    b->dados[JO].capitulos[39].versos[24] = _("Tremendo e enfurecido devora a terra, e não se contém ao som da trombeta.");
    b->dados[JO].capitulos[39].versos[25] = _("Toda vez que soa a trombeta, diz: Eia! E de longe cheira a guerra, e o trovão dos capitães e os gritos.");
    b->dados[JO].capitulos[39].versos[26] = _("É pelo teu entendimento que se eleva o gavião, e estende as suas asas para o sul?");
    b->dados[JO].capitulos[39].versos[27] = _("Ou se remonta a águia ao teu mandado, e põe no alto o seu ninho?");
    b->dados[JO].capitulos[39].versos[28] = _("Mora nas penhas e ali tem a sua pousada, no cume das penhas, no lugar seguro.");
    b->dados[JO].capitulos[39].versos[29] = _("Dali descobre a presa; seus olhos a avistam de longe.");
    b->dados[JO].capitulos[39].versos[30] = _("Seus filhos chupam o sangue; e onde há mortos, ela aí está.");

    b->dados[JO].capitulos[40].versos[1] = _("Disse mais o Senhor a Jó:");
    b->dados[JO].capitulos[40].versos[2] = _("Contenderá contra o Todo-Poderoso o censurador? Quem assim argüi a Deus, responda a estas coisas.");
    b->dados[JO].capitulos[40].versos[3] = _("Então Jó respondeu ao Senhor, e disse:");
    b->dados[JO].capitulos[40].versos[4] = _("Eis que sou vil; que te responderia eu? Antes ponho a minha mão sobre a boca.");
    b->dados[JO].capitulos[40].versos[5] = _("Uma vez tenho falado, e não replicarei; ou ainda duas vezes, porém não prosseguirei.");
    b->dados[JO].capitulos[40].versos[6] = _("Então, do meio do redemoinho, o Senhor respondeu a Jó:");
    b->dados[JO].capitulos[40].versos[7] = _("Cinge agora os teus lombos como homem; eu te perguntarei a ti, e tu me responderás.");
    b->dados[JO].capitulos[40].versos[8] = _("Farás tu vão também o meu juízo, ou me condenarás para te justificares a ti?");
    b->dados[JO].capitulos[40].versos[9] = _("Ou tens braço como Deus; ou podes trovejar com uma voz como a dele?");
    b->dados[JO].capitulos[40].versos[10] = _("Orna-te, pois, de excelência e dignidade, e veste-te de glória e de esplendor.");
    b->dados[JO].capitulos[40].versos[11] = _("Derrama as inundações da tua ira, e atenta para todo soberbo, e abate-o.");
    b->dados[JO].capitulos[40].versos[12] = _("Olha para todo soberbo, e humilha-o, e calca aos pés os ímpios onde estão.");
    b->dados[JO].capitulos[40].versos[13] = _("Esconde-os juntamente no pó; ata-lhes os rostos no lugar escondido.");
    b->dados[JO].capitulos[40].versos[14] = _("Então também eu de ti confessarei que a tua mão direita te poderá salvar.");
    b->dados[JO].capitulos[40].versos[15] = _("Contempla agora o hipopótamo, que eu criei como a ti, que come a erva como o boi.");
    b->dados[JO].capitulos[40].versos[16] = _("Eis que a sua força está nos seus lombos, e o seu poder nos músculos do seu ventre.");
    b->dados[JO].capitulos[40].versos[17] = _("Ele enrija a sua cauda como o cedro; os nervos das suas coxas são entretecidos.");
    b->dados[JO].capitulos[40].versos[18] = _("Os seus ossos são como tubos de bronze, as suas costelas como barras de ferro.");
    b->dados[JO].capitulos[40].versos[19] = _("Ele é obra prima dos caminhos de Deus; aquele que o fez o proveu da sua espada.");
    b->dados[JO].capitulos[40].versos[20] = _("Em verdade os montes lhe produzem pasto, onde todos os animais do campo folgam.");
    b->dados[JO].capitulos[40].versos[21] = _("Deita-se debaixo dos lotos, no esconderijo dos canaviais e no pântano.");
    b->dados[JO].capitulos[40].versos[22] = _("Os lotos cobrem-no com sua sombra; os salgueiros do ribeiro o cercam.");
    b->dados[JO].capitulos[40].versos[23] = _("Eis que se um rio trasborda, ele não treme; sente-se seguro ainda que o Jordão se levante até a sua boca.");
    b->dados[JO].capitulos[40].versos[24] = _("Poderá alguém apanhá-lo quando ele estiver de vigia, ou com laços lhe furar o nariz?");

    b->dados[JO].capitulos[41].versos[1] = _("Poderás tirar com anzol o leviatã, ou apertar-lhe a língua com uma corda?");
    b->dados[JO].capitulos[41].versos[2] = _("Poderás meter-lhe uma corda de junco no nariz, ou com um gancho furar a sua queixada?");
    b->dados[JO].capitulos[41].versos[3] = _("Porventura te fará muitas súplicas, ou brandamente te falará?");
    b->dados[JO].capitulos[41].versos[4] = _("Fará ele aliança contigo, ou o tomarás tu por servo para sempre?");
    b->dados[JO].capitulos[41].versos[5] = _("Brincarás com ele, como se fora um pássaro, ou o prenderás para tuas meninas?");
    b->dados[JO].capitulos[41].versos[6] = _("Farão os sócios de pesca tráfico dele, ou o dividirão entre os negociantes?");
    b->dados[JO].capitulos[41].versos[7] = _("Poderás encher-lhe a pele de arpões, ou a cabeça de fisgas?");
    b->dados[JO].capitulos[41].versos[8] = _("Põe a tua mão sobre ele; lembra-te da peleja; nunca mais o farás!");
    b->dados[JO].capitulos[41].versos[9] = _("Eis que é vã a esperança de apanhá-lo; pois não será um homem derrubado só ao vê-lo?");
    b->dados[JO].capitulos[41].versos[10] = _("Ninguém há tão ousado, que se atreva a despertá-lo; quem, pois, é aquele que pode erguer-se diante de mim?");
    b->dados[JO].capitulos[41].versos[11] = _("Quem primeiro me deu a mim, para que eu haja de retribuir-lhe? Pois tudo quanto existe debaixo de todo céu é meu.");
    b->dados[JO].capitulos[41].versos[12] = _("Não me calarei a respeito dos seus membros, nem da sua grande força, nem da graça da sua estrutura.");
    b->dados[JO].capitulos[41].versos[13] = _("Quem lhe pode tirar o vestido exterior? Quem lhe penetrará a couraça dupla?");
    b->dados[JO].capitulos[41].versos[14] = _("Quem jamais abriu as portas do seu rosto? Pois em roda dos seus dentes está o terror.");
    b->dados[JO].capitulos[41].versos[15] = _("As suas fortes escamas são o seu orgulho, cada uma fechada como por um selo apertado.");
    b->dados[JO].capitulos[41].versos[16] = _("Uma à outra se chega tão perto, que nem o ar passa por entre elas.");
    b->dados[JO].capitulos[41].versos[17] = _("Umas às outras se ligam; tanto aderem entre si, que não se podem separar.");
    b->dados[JO].capitulos[41].versos[18] = _("Os seus espirros fazem resplandecer a luz, e os seus olhos são como as pestanas da alva.");
    b->dados[JO].capitulos[41].versos[19] = _("Da sua boca saem tochas; faíscas de fogo saltam dela.");
    b->dados[JO].capitulos[41].versos[20] = _("Dos seus narizes procede fumaça, como de uma panela que ferve, e de juncos que ardem.");
    b->dados[JO].capitulos[41].versos[21] = _("O seu hálito faz incender os carvões, e da sua boca sai uma chama.");
    b->dados[JO].capitulos[41].versos[22] = _("No seu pescoço reside a força; e diante dele anda saltando o terror.");
    b->dados[JO].capitulos[41].versos[23] = _("Os tecidos da sua carne estão pegados entre si; ela é firme sobre ele, não se pode mover.");
    b->dados[JO].capitulos[41].versos[24] = _("O seu coração é firme como uma pedra; sim, firme como a pedra inferior duma mó.");
    b->dados[JO].capitulos[41].versos[25] = _("Quando ele se levanta, os valentes são atemorizados, e por causa da consternação ficam fora de si.");
    b->dados[JO].capitulos[41].versos[26] = _("Se alguém o atacar com a espada, essa não poderá penetrar; nem tampouco a lança, nem o dardo, nem o arpão.");
    b->dados[JO].capitulos[41].versos[27] = _("Ele considera o ferro como palha, e o bronze como pau podre.");
    b->dados[JO].capitulos[41].versos[28] = _("A seta não o poderá fazer fugir; para ele as pedras das fundas se tornam em restolho.");
    b->dados[JO].capitulos[41].versos[29] = _("Os bastões são reputados como juncos, e ele se ri do brandir da lança.");
    b->dados[JO].capitulos[41].versos[30] = _("Debaixo do seu ventre há pontas agudas; ele se estende como um trilho sobre o lodo.");
    b->dados[JO].capitulos[41].versos[31] = _("As profundezas faz ferver, como uma panela; torna o mar como uma vasilha de ungüento.");
    b->dados[JO].capitulos[41].versos[32] = _("Após si deixa uma vereda luminosa; parece o abismo tornado em brancura de cãs.");
    b->dados[JO].capitulos[41].versos[33] = _("Na terra não há coisa que se lhe possa comparar; pois foi feito para estar sem pavor.");
    b->dados[JO].capitulos[41].versos[34] = _("Ele vê tudo o que é alto; é rei sobre todos os filhos da soberba.");

    b->dados[JO].capitulos[42].versos[1] = _("Então respondeu Jó ao Senhor:");
    b->dados[JO].capitulos[42].versos[2] = _("Bem sei eu que tudo podes, e que nenhum dos teus propósitos pode ser impedido.");
    b->dados[JO].capitulos[42].versos[3] = _("Quem é este que sem conhecimento obscurece o conselho? por isso falei do que não entendia; coisas que para mim eram demasiado maravilhosas, e que eu não conhecia.");
    b->dados[JO].capitulos[42].versos[4] = _("Ouve, pois, e eu falarei; eu te perguntarei, e tu me responderas.");
    b->dados[JO].capitulos[42].versos[5] = _("Com os ouvidos eu ouvira falar de ti; mas agora te vêem os meus olhos.");
    b->dados[JO].capitulos[42].versos[6] = _("Pelo que me abomino, e me arrependo no pó e na cinza.");
    b->dados[JO].capitulos[42].versos[7] = _("Sucedeu pois que, acabando o Senhor de dizer a Jó aquelas palavras, o Senhor disse a Elifaz, o temanita: A minha ira se acendeu contra ti e contra os teus dois amigos, porque não tendes falado de mim o que era reto, como o meu servo Jó.");
    b->dados[JO].capitulos[42].versos[8] = _("Tomai, pois, sete novilhos e sete carneiros, e ide ao meu servo Jó, e oferecei um holocausto por vós; e o meu servo Jó orará por vós; porque deveras a ele aceitarei, para que eu não vos trate conforme a vossa estultícia; porque vós não tendes falado de mim o que era reto, como o meu servo Jó.");
    b->dados[JO].capitulos[42].versos[9] = _("Então foram Elifaz o temanita, e Bildade o suíta, e Zofar o naamatita, e fizeram como o Senhor lhes ordenara; e o Senhor aceitou a Jó.");
    b->dados[JO].capitulos[42].versos[10] = _("O Senhor, pois, virou o cativeiro de Jó, quando este orava pelos seus amigos; e o Senhor deu a Jó o dobro do que antes possuía.");
    b->dados[JO].capitulos[42].versos[11] = _("Então vieram ter com ele todos os seus irmãos, e todas as suas irmãs, e todos quantos dantes o conheceram, e comeram com ele pão em sua casa; condoeram-se dele, e o consolaram de todo o mal que o Senhor lhe havia enviado; e cada um deles lhe deu uma peça de dinheiro e um pendente de ouro.");
    b->dados[JO].capitulos[42].versos[12] = _("E assim abençoou o Senhor o último estado de Jó, mais do que o primeiro; pois Jó chegou a ter catorze mil ovelhas, seis mil camelos, mil juntas de bois e mil jumentas.");
    b->dados[JO].capitulos[42].versos[13] = _("Também teve sete filhos e três filhas.");
    b->dados[JO].capitulos[42].versos[14] = _("E chamou o nome da primeira Jemima, e o nome da segunda Quezia, e o nome da terceira Quéren-Hapuque.");
    b->dados[JO].capitulos[42].versos[15] = _("E em toda a terra não se acharam mulheres tão formosas como as filhas de Jó; e seu pai lhes deu herança entre seus irmãos.");
    b->dados[JO].capitulos[42].versos[16] = _("Depois disto viveu Jó cento e quarenta anos, e viu seus filhos, e os filhos de seus filhos: até a quarta geração.");
    b->dados[JO].capitulos[42].versos[17] = _("Então morreu Jó, velho e cheio de dias.");

}
